  /**
   * F-1: UI 텍스트 번역 헬퍼
   * @param {string} key - i18n 키
   * @param {string} [overrideLang] - 지정 시 해당 언어 사용, 미지정 시 settings.uiLanguage
   * @returns {string} 번역된 텍스트 (없으면 key 자체 반환)
   */
  function t(key, overrideLang) {
    var lang = overrideLang || (settings && settings.uiLanguage) || "ko";
    var dict = _i18n[lang];
    if (dict && dict[key] != null) return dict[key];
    // fallback: en → ko → key
    if (lang !== "en" && _i18n.en && _i18n.en[key] != null) return _i18n.en[key];
    if (lang !== "ko" && _i18n.ko && _i18n.ko[key] != null) return _i18n.ko[key];
    return key;
  }

  function tf(key, vars, overrideLang) {
    var text = t(key, overrideLang);
    var values = vars || {};
    Object.keys(values).forEach(function(name) {
      text = text.replace(new RegExp("\\{" + name + "\\}", "g"), String(values[name]));
    });
    return text;
  }

  const RISU_USER_PLACEHOLDER = "{{user}}";
  const PLAYER_ENTITY_TOKEN = "__PLAYER__";
  function _normalizePlayerEntityLabelKey(value) {
    return String(value || "").trim().toLowerCase().replace(/[^0-9a-z가-힣\u3040-\u30ff\u4e00-\u9fff]+/g, "");
  }

  const PLAYER_ENTITY_LABEL_KEYS = new Set([
    PLAYER_ENTITY_TOKEN,
    "player",
    "user",
    "participant",
    "conversation partner",
    "chat partner",
    "counterpart",
    "interlocutor",
    "플레이어",
    "유저",
    "사용자",
    "대화 상대",
    "상대방",
    "ユーザー",
    "プレイヤー",
    "参加者"
  ].map(_normalizePlayerEntityLabelKey).filter(Boolean));

  function _isPlayerEntityLabelText(value) {
    var key = _normalizePlayerEntityLabelKey(value);
    return !!key && PLAYER_ENTITY_LABEL_KEYS.has(key);
  }

  function _readNestedString(root, path) {
    try {
      var cur = root;
      for (var i = 0; i < path.length; i++) {
        if (cur == null) return "";
        cur = cur[path[i]];
      }
      return typeof cur === "string" ? cur.trim() : "";
    } catch {
      return "";
    }
  }

  function resolveRuntimePlayerDisplayName() {
    try {
      if (typeof DBState !== "undefined" && DBState && DBState.db && typeof DBState.db.username === "string") {
        var directName = DBState.db.username.trim();
        if (directName && !_isPlayerEntityLabelText(directName)) return directName;
      }
    } catch {}
    try {
      if (R && R.DBState && R.DBState.db && typeof R.DBState.db.username === "string") {
        var risuName = R.DBState.db.username.trim();
        if (risuName && !_isPlayerEntityLabelText(risuName)) return risuName;
      }
    } catch {}
    try {
      var globalObj = typeof globalThis !== "undefined"
        ? globalThis
        : (typeof window !== "undefined" ? window : null);
      if (!globalObj) return "";
      var paths = [
        ["DBState", "db", "username"],
        ["db", "username"],
      ];
      for (var i = 0; i < paths.length; i++) {
        var candidate = _readNestedString(globalObj, paths[i]);
        if (candidate && !_isPlayerEntityLabelText(candidate)) return candidate;
      }
    } catch {}
    return "";
  }

  function getDisplayPlayerLabel() {
    return resolveRuntimePlayerDisplayName() || RISU_USER_PLACEHOLDER;
  }

  function sanitizePlayerTokenForDisplayText(value) {
    var text = value == null ? "" : String(value);
    if (!text) return text;

    var displayLabel = getDisplayPlayerLabel();
    if (text.indexOf(PLAYER_ENTITY_TOKEN) >= 0) {
      text = text.split(PLAYER_ENTITY_TOKEN).join(displayLabel);
    }
    text = text.replace(/\{\{\s*user\s*\}\}/gi, function() {
      return displayLabel;
    });
    text = text.replace(/<\s*user\s*>/gi, function() {
      return displayLabel;
    });
    return text;
  }

  function isPlayerEntityLabel(value) {
    return _isPlayerEntityLabelText(value);
  }

  function sanitizeNarrativePlayerTextForDisplay(value, opts) {
    var text = value == null ? "" : String(value);
    if (!text) return text;
    if (opts && opts.stripLeadingPlayerAlias) {
      text = text.replace(/^\s*(?:\{\{\s*user\s*\}\}|<\s*user\s*>|__PLAYER__|사용자|유저|user|player)(?:\s*[:：-]\s*|\s*(?:가|이|는|은|를|을|와|과|의)\s*)/i, "").trim();
    }
    return sanitizePlayerTokenForDisplayText(text);
  }

  function getDisplayKgItems(items) {
    if (!Array.isArray(items)) return [];
    return items.filter(function(item) {
      return item && !isPlayerEntityLabel(item.subject) && !isPlayerEntityLabel(item.object);
    });
  }

  function getMemoryPreviewTextForDisplay(item) {
    if (!item) return "";
    var preview = item.summary_preview || "";
    if (!preview && item.summary_json) {
      try {
        var parsed = typeof item.summary_json === "string" ? JSON.parse(item.summary_json) : item.summary_json;
        if (parsed && typeof parsed === "object") {
          preview = parsed.turn_summary || parsed.summary || "";
        }
      } catch {}
    }
    return sanitizeNarrativePlayerTextForDisplay(preview, { stripLeadingPlayerAlias: true });
  }

  function formatMemoryJsonForDisplay(rawValue) {
    var parsed = rawValue;
    if (typeof rawValue === "string") {
      try {
        parsed = JSON.parse(rawValue);
      } catch {
        return sanitizeNarrativePlayerTextForDisplay(rawValue, { stripLeadingPlayerAlias: true });
      }
    }
    if (!parsed || typeof parsed !== "object") {
      return sanitizeNarrativePlayerTextForDisplay(parsed, { stripLeadingPlayerAlias: true });
    }

    var projected;
    try {
      projected = JSON.parse(JSON.stringify(parsed));
    } catch {
      projected = parsed;
    }

    if (typeof projected.turn_summary === "string") {
      projected.turn_summary = sanitizeNarrativePlayerTextForDisplay(projected.turn_summary, { stripLeadingPlayerAlias: true });
    }
    if (Array.isArray(projected.kg_triples)) {
      projected.kg_triples = projected.kg_triples.filter(function(triple) {
        return triple && !isPlayerEntityLabel(triple.subject) && !isPlayerEntityLabel(triple.object);
      });
    }
    if (Array.isArray(projected.character_deltas)) {
      projected.character_deltas = projected.character_deltas.filter(function(delta) {
        return delta && !isPlayerEntityLabel(delta.name);
      }).map(function(delta) {
        if (!delta || typeof delta !== "object") return delta;
        var next = Object.assign({}, delta);
        if (Array.isArray(next.relationships)) {
          next.relationships = next.relationships.filter(function(rel) {
            return rel && !isPlayerEntityLabel(rel.target);
          });
        }
        return next;
      });
    }
    if (Array.isArray(projected.pending_threads)) {
      projected.pending_threads = projected.pending_threads.map(function(thread) {
        if (!thread || typeof thread !== "object") return thread;
        var next = Object.assign({}, thread);
        if (isPlayerEntityLabel(next.owner)) next.owner = null;
        if (isPlayerEntityLabel(next.target)) next.target = null;
        if (typeof next.title === "string") {
          next.title = sanitizeNarrativePlayerTextForDisplay(next.title, { stripLeadingPlayerAlias: true });
        }
        if (typeof next.details === "string") {
          next.details = sanitizeNarrativePlayerTextForDisplay(next.details, { stripLeadingPlayerAlias: false });
        }
        return next;
      });
    }

    return JSON.stringify(projected, null, 2);
  }

  function formatDisplayEntityLabel(value) {
    var text = sanitizePlayerTokenForDisplayText(value == null ? "" : String(value).trim());
    return text || "?";
  }

  function formatDisplayKgTripleLine(item, plainArrow) {
    var subject = formatDisplayEntityLabel(item && item.subject);
    var predicate = sanitizePlayerTokenForDisplayText(item && item.predicate != null ? String(item.predicate).trim() : "") || "?";
    var object = formatDisplayEntityLabel(item && item.object);
    return plainArrow
      ? subject + " → " + predicate + " → " + object
      : subject + " —(" + predicate + ")→ " + object;
  }

  // pluginStorage: RisuAI 제공 영속 저장소 (재시작/새로고침 후에도 유지).
  // localStorage:  동기 캐시 (빠른 읽기용, iframe 세션 내에서만 유지).
  // 인메모리 _mem: localStorage도 차단될 때의 최후 fallback.
  //
  // 쓰기: pluginStorage (영속) + localStorage/인메모리 (캐시) 둘 다 기록.
  // 읽기: 동기 시 localStorage/인메모리 캐시, 비동기 시 pluginStorage 우선.
  // ──────────────────────────────────────────────────────────────
  const _mem = {};
  const _persistentKnownValues = new Map();
  const _persistentPendingWrites = new Map();
  let _storageOk = false;
  try { localStorage.setItem("__test", "1"); localStorage.removeItem("__test"); _storageOk = true; } catch {}

  function normalizePersistentValue(value) {
    return String(value);
  }

  /** pluginStorage가 사용 가능한지 여부 */
  function _hasPluginStorage() {
    return !!(R && R.pluginStorage && typeof R.pluginStorage.getItem === "function");
  }

  /** 동기 캐시에서 읽기 (즉시 반환, 초기화 전 fallback용) */
  function safeStorageGet(key) {
    if (_storageOk) try { return localStorage.getItem(key); } catch {}
    return _mem[key] ?? null;
  }

  /** 동기 캐시에 쓰기 */
  function safeStorageSet(key, value) {
    const storageValue = normalizePersistentValue(value);
    if (_storageOk) try {
      if (localStorage.getItem(key) !== storageValue) localStorage.setItem(key, storageValue);
    } catch {}
    _mem[key] = storageValue;
  }

  /** pluginStorage + 동기 캐시 둘 다에 쓰기 (비동기) */
  async function persistentSet(key, value) {
    const storageValue = normalizePersistentValue(value);
    // 동기 캐시 즉시 갱신
    safeStorageSet(key, storageValue);
    // pluginStorage 영속 저장 (실패해도 캐시에는 이미 기록됨)
    if (!_hasPluginStorage()) {
      _persistentKnownValues.set(key, storageValue);
      return;
    }
    if (_persistentKnownValues.get(key) === storageValue) return;
    const pending = _persistentPendingWrites.get(key);
    if (pending && pending.value === storageValue) {
      await pending.promise;
      return;
    }

    const token = {};
    const writePromise = (async function() {
      try {
        await R.pluginStorage.setItem(key, storageValue);
        if (safeStorageGet(key) === storageValue) {
          _persistentKnownValues.set(key, storageValue);
        }
      } catch (err) {
        warnLog("pluginStorage.setItem failed:", err.message);
      } finally {
        const current = _persistentPendingWrites.get(key);
        if (current && current.token === token) _persistentPendingWrites.delete(key);
      }
    })();
    _persistentPendingWrites.set(key, { value: storageValue, promise: writePromise, token });
    await writePromise;
  }

  /** pluginStorage에서 읽기 시도 → 실패 시 동기 캐시 fallback (비동기) */
  async function persistentGet(key) {
    if (_hasPluginStorage()) {
      try {
        const val = await R.pluginStorage.getItem(key);
        if (val != null) {
          const storageValue = normalizePersistentValue(val);
          // 동기 캐시도 동기화
          safeStorageSet(key, storageValue);
          _persistentKnownValues.set(key, storageValue);
          return val;
        }
      } catch (err) {
        warnLog("pluginStorage.getItem failed:", err.message);
      }
    }
    // pluginStorage 불가능하거나 값이 없으면 동기 캐시에서
    return safeStorageGet(key);
  }

  function safeStorageRemove(key) {
    if (!key) return;
    if (_storageOk) try { localStorage.removeItem(key); } catch {}
    delete _mem[key];
  }

  async function persistentDelete(key) {
    if (!key) return;
    safeStorageRemove(key);
    _persistentKnownValues.delete(key);
    _persistentPendingWrites.delete(key);
    if (_hasPluginStorage()) {
      try {
        if (typeof R.pluginStorage.removeItem === "function") {
          await R.pluginStorage.removeItem(key);
        } else {
          await R.pluginStorage.setItem(key, "");
        }
      } catch (err) {
        warnLog("pluginStorage.removeItem failed:", err.message);
      }
    }
  }

