      clean = sanitizeForCritic(String(clean || ""));
      if (!String(clean || "").trim()) return "";
      if (isLikelyEffectiveInputScaffoldText(clean)) return "";
      if (looksLikeReasoningTransitionOnlyText(clean)) return "";
