    const mode = String(trace.resolvedMode || trace.requestedMode || "unknown");
    const idx = trace.insertIndex != null ? "#" + String(trace.insertIndex) : "";
    const fb = trace.fallbackUsed && trace.fallbackReason ? " fallback:" + String(trace.fallbackReason) : "";
