              failReasons: currentFailReasons,
              llmConfigTrace: _ctResult && (_ctResult.llm_config_trace || _ctResult.trace_handoff?.llm_config_trace) || null,
              chatLogsSaved: _ctResult && typeof _ctResult.chat_logs_saved === "number" ? _ctResult.chat_logs_saved : null,
              memoriesSaved: _ctResult && typeof _ctResult.memories_saved === "number" ? _ctResult.memories_saved : null,
              evidenceSaved: _ctResult && typeof _ctResult.evidence_saved === "number" ? _ctResult.evidence_saved : null,
              kgTriplesSaved: _ctResult && typeof _ctResult.kg_triples_saved === "number" ? _ctResult.kg_triples_saved : null,
              subjectiveEntityMemoriesSaved: _ctResult && typeof _ctResult.subjective_entity_memories_saved === "number" ? _ctResult.subjective_entity_memories_saved : null,
