              rawStatus: ctRaw && ctRaw.status ? String(ctRaw.status) : "",
              derivedStatus: ctDerived && ctDerived.status ? String(ctDerived.status) : "",
              vectorStatus: ctVector && ctVector.status ? String(ctVector.status) : "",
