  // Sprint 3-E-4: Critic Feedback state
  const _feedback = {
    // { "mem_42": { feedback_value: "up", ... }, "kg_7": { ... } }
    latest: {},
    // { "mem_42": "saving" | "ok" | "error" }
    status: {},
  };

  function feedbackKey(type, id) {
    return type + "_" + id;
  }

  async function feedbackFetchLatest(targetType, ids) {
    if (!ids || ids.length === 0) return;
    const sid = explorerSessionId();
    if (!sid) return;
    const tt = targetType === "mem" ? "memory" : "kg_triple";
    try {
      const result = await bridgeFetch(
        "/feedback/latest?chat_session_id=" + encodeURIComponent(sid) +
        "&target_type=" + encodeURIComponent(tt) +
        "&target_ids=" + ids.join(",")
      );
      if (result && result.status === "ok" && result.feedbacks) {
        for (const [tid, fb] of Object.entries(result.feedbacks)) {
          _feedback.latest[feedbackKey(targetType === "mem" ? "mem" : "kg", Number(tid))] = fb;
        }
      }
    } catch (err) {
      debugLog("feedbackFetchLatest error:", err.message);
    }
  }

  async function feedbackSubmit(type, id, value, note) {
    const sid = explorerSessionId();
    if (!sid) return;
    const key = feedbackKey(type, id);
    const tt = type === "mem" ? "memory" : "kg_triple";
    _feedback.status[key] = "saving";
    try {
      refreshExplorerUI();
    } catch { /* silent */ }
    try {
      const result = await bridgeFetch("/feedback", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          chat_session_id: sid,
          target_type: tt,
          target_id: id,
          feedback_value: value,
          feedback_note: note || null,
        }),
      });
      if (result && result.status === "ok") {
        _feedback.status[key] = "ok";
        _feedback.latest[key] = { feedback_value: value, feedback_note: note || null };
      } else {
        _feedback.status[key] = "error";
        debugLog("feedbackSubmit failed:", result);
      }
    } catch (err) {
      _feedback.status[key] = "error";
      debugLog("feedbackSubmit error:", err.message);
    }
    try {
      refreshExplorerUI();
    } catch { /* silent */ }
  }

  function explorerSessionId() {
    return _explorer.selectedSessionId || null;
  }

  async function explorerFetchSessions() {
    _explorer.sessionsLoading = true;
    _explorer.sessionsError = "";
    try {
      await refreshSessionDisplayLookupFromRuntime();
      const result = await bridgeFetch("/sessions", { method: "GET", timeoutMs: getRequestTimeoutSettingMs() });
      const sessions = Array.isArray(result && result.sessions)
        ? result.sessions
        : Array.isArray(result && result.items)
          ? result.items
          : [];
      let normalized = sessions.filter((session) => session && session.chat_session_id);
      if (!normalized.length && _timelineState && Array.isArray(_timelineState.sessions) && _timelineState.sessions.length) {
        normalized = _timelineState.sessions.filter((session) => session && session.chat_session_id);
      }
      const liveSid = String(_explorer.activeChatSessionId || "").trim();
      if (liveSid && !timelineIsPlaceholderSessionId(liveSid) && !normalized.some((session) => String(session.chat_session_id || "") === liveSid)) {
        normalized.unshift({
          chat_session_id: liveSid,
          chat_logs_count: 0,
          memories_count: 0,
          kg_triples_count: 0,
          last_activity: "",
          synthetic_current: true,
        });
      }
      _explorer.sessions = normalized;
      normalizeExplorerSelectedSessionForActiveTab();
    } catch (err) {
      const timelineSessions = _timelineState && Array.isArray(_timelineState.sessions)
        ? _timelineState.sessions.filter((session) => session && session.chat_session_id)
        : [];
      if (timelineSessions.length) {
        _explorer.sessions = timelineSessions;
      } else if (!Array.isArray(_explorer.sessions) || !_explorer.sessions.length) {
        const liveSid = String(_explorer.activeChatSessionId || "").trim();
        _explorer.sessions = liveSid && !timelineIsPlaceholderSessionId(liveSid)
          ? [{
              chat_session_id: liveSid,
              chat_logs_count: 0,
              memories_count: 0,
              kg_triples_count: 0,
              synthetic_current: true,
            }]
          : [];
      }
      _explorer.sessionsError = err && err.message ? err.message : "Explorer session list load failed.";
      normalizeExplorerSelectedSessionForActiveTab();
    }
    _explorer.sessionsLoading = false;
  }

  function explorerVisibleSessions() {
    const primary = Array.isArray(_explorer.sessions)
      ? _explorer.sessions.filter((session) => session && session.chat_session_id)
      : [];
    if (primary.length) return primary;
    return _timelineState && Array.isArray(_timelineState.sessions)
      ? _timelineState.sessions.filter((session) => session && session.chat_session_id)
      : [];
  }

  function normalizeExplorerSelectedSessionForActiveTab() {
    try {
      const sessions = explorerVisibleSessions();
      const selectedSid = _explorer.selectedSessionId || null;
      const liveSid = _explorer.activeChatSessionId || null;
      const knownSessionIds = new Set(sessions.map(s => s && s.chat_session_id).filter(Boolean));

      if (selectedSid && !knownSessionIds.has(selectedSid)) {
        _explorer.selectedSessionId = null;
        return;
      }

      if (!selectedSid && liveSid && knownSessionIds.has(liveSid)) {
        _explorer.selectedSessionId = liveSid;
        return;
      }
    } catch { /* silent */ }
  }

  function shouldUseExplorerChatLogsFallback() {
    return false;
  }

  function explorerChatLogsQuerySessionId() {
    return explorerSessionId();
  }

  async function explorerFetchChatLogs(reset = false) {
    const state = _explorer.chatLogs;
    if (state.loading && !reset) return;
    if (reset) { state.items = []; state.offset = 0; state.total = 0; state.hasMore = false; }
    const requestId = (Number(state.requestId || 0) + 1);
    state.requestId = requestId;
    state.loading = true;
    const requestSid = explorerChatLogsQuerySessionId();
    try {
      const sid = requestSid;
      if (!sid) {
        state.items = [];
        state.offset = 0;
        state.total = 0;
        state.hasMore = false;
        return;
      }
      const params = new URLSearchParams();
      if (sid) params.set("chat_session_id", sid);
      params.set("limit", String(EXPLORER_PAGE_SIZE));
      params.set("offset", String(state.offset));
      const result = await safeCall(
        () => bridgeFetch("/explorer/chat_logs?" + params.toString()),
        null, "explorerFetchChatLogs"
      );
      if (result && Array.isArray(result.items)) {
        if (state.requestId !== requestId || explorerChatLogsQuerySessionId() !== requestSid) return;
        state.items = reset ? result.items : state.items.concat(result.items);
        state.total = result.total || 0;
        state.hasMore = !!result.has_more;
        state.offset = state.items.length;
      }
    } catch { /* silent */ }
    finally {
      if (state.requestId === requestId) state.loading = false;
    }
  }

