  function explorerPagedStateForTab(tab) {
    if (tab === "chat_logs") return _explorer.chatLogs;
    if (tab === "memories") return _explorer.memories;
    if (tab === "direct_evidence") return _explorer.directEvidence;
    if (tab === "kg_triples") return _explorer.kgTriples;
    if (tab === "episodes") return _explorer.episodes;
    if (tab === "chapters") return _explorer.chapters;
    if (tab === "arcs") return _explorer.arcs;
    if (tab === "sagas") return _explorer.sagas;
    return null;
  }

  function explorerShowTabLoading(tab) {
    const state = explorerPagedStateForTab(tab);
    if (!state) return;
    state.items = [];
    state.offset = 0;
    state.total = 0;
    state.hasMore = false;
    state.loading = true;
    if (tab === "episodes") {
      ["chapters", "arcs", "sagas"].forEach(kind => {
        const hierarchyState = explorerPagedStateForTab(kind);
        if (!hierarchyState) return;
        hierarchyState.items = [];
        hierarchyState.offset = 0;
        hierarchyState.total = 0;
        hierarchyState.hasMore = false;
        hierarchyState.loading = true;
      });
    }
    if (tab === "direct_evidence") {
      state.stateCounts = null;
      state.stateContract = null;
    }
  }

  function explorerRenderActiveTabShell() {
    try {
      document.querySelectorAll(".mo-ex-tab").forEach(btn => {
        const active = btn.dataset && btn.dataset.tab === _explorer.activeTab;
        btn.classList.toggle("mo-ex-tab-active", !!active);
      });
      const content = document.getElementById("mo-ex-content");
      if (content) content.innerHTML = renderExplorerContent();
    } catch { /* silent */ }
  }

  async function explorerLoadTab(tab, reset = true) {
    _explorer.activeTab = tab;
    if (tab === "chat_logs") await explorerFetchChatLogs(reset);
    else if (tab === "memories") {
      await explorerFetchMemories(reset);
      // Sprint 3-E-4: fetch latest feedback for visible memories
      const ids = _explorer.memories.items.map(m => m.id).filter(Boolean);
      if (ids.length > 0) feedbackFetchLatest("mem", ids).catch(() => {});
    }
    else if (tab === "direct_evidence") {
      await explorerFetchDirectEvidence(reset);
    }
    else if (tab === "kg_triples") {
      await explorerFetchKgTriples(reset);
      // Sprint 3-E-4: fetch latest feedback for visible kg_triples
      const ids = _explorer.kgTriples.items.map(k => k.id).filter(Boolean);
      if (ids.length > 0) feedbackFetchLatest("kg", ids).catch(() => {});
    }
    else if (tab === "episodes") {
      await explorerFetchHierarchySummaries(reset);
    }
    else if (tab === "trust") {
      await explorerFetchTrust();
    }
    else if (tab === "world") {
      await explorerFetchWorldGraph();
    }
    else if (tab === "entities") {
      await explorerFetchEntities();
    }
  }

  // ── Entities tab: fetch ──────────────────────────────────────────────────
  function explorerEntityMemoryBundleKey(item) {
    if (!item || typeof item !== "object") return "";
    return [
      String(item.owner_entity_key || "").trim(),
      String(item.owner_entity_name || "").trim(),
      String(item.source_chat_session_id || "").trim(),
    ].join("\x1f");
  }

  function explorerSelectedEntityMemoryBundle() {
    const ent = _explorer.entities;
    const key = String(ent.selectedMemoryBundleKey || "");
    return (Array.isArray(ent.memoryBundles) ? ent.memoryBundles : [])
      .find((item) => explorerEntityMemoryBundleKey(item) === key) || null;
  }

  async function explorerFetchSelectedEntityMemoryItems() {
    const ent = _explorer.entities;
    const bundle = explorerSelectedEntityMemoryBundle();
    if (!bundle) {
      ent.memoryItems = [];
      ent.memoryError = null;
      ent.memoryLoading = false;
      return;
    }
    ent.memoryLoading = true;
    ent.memoryError = null;
    try {
      const params = new URLSearchParams();
      params.set("owner_entity_key", String(bundle.owner_entity_key || ""));
      params.set("owner_entity_name", String(bundle.owner_entity_name || ""));
      params.set("source_chat_session_id", String(bundle.source_chat_session_id || explorerSessionId() || ""));
      params.set("limit", "80");
      const data = await bridgeFetch("/subjective-entity-memories?" + params.toString(), {
        method: "GET",
        timeoutMs: getRequestTimeoutSettingMs(),
      });
      ent.memoryItems = data && Array.isArray(data.items) ? data.items : [];
    } catch (e) {
      ent.memoryItems = [];
      ent.memoryError = e && e.message ? e.message : String(e);
    }
    ent.memoryLoading = false;
  }

  async function explorerFetchEntities() {
    const sid = explorerSessionId();
    const ent = _explorer.entities;
    if (!sid) {
      ent.characters = []; ent.locations = []; ent.items = []; ent.memoryBundles = []; ent.memoryItems = [];
      ent.error = "세션 없음"; ent.loading = false; return;
    }
    ent.loading = true; ent.error = null;
    try {
      const kgParams = new URLSearchParams();
      kgParams.set("chat_session_id", sid);
      kgParams.set("limit", "200");
      kgParams.set("offset", "0");
      const bundleParams = new URLSearchParams();
      bundleParams.set("source_chat_session_id", sid);
      const [charRes, wrRes, kgRes, bundleRes] = await Promise.all([
        safeCall(() => bridgeFetch("/characters/" + encodeURIComponent(sid), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "entitiesFetchChars"),
        safeCall(() => bridgeFetch("/world-rules/" + encodeURIComponent(sid), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "entitiesFetchWorldRules"),
        safeCall(() => bridgeFetch("/explorer/kg_triples?" + kgParams.toString(), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "entitiesFetchKg"),
        safeCall(() => bridgeFetch("/subjective-entity-memories/entities?" + bundleParams.toString(), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "entitiesFetchSubjectiveMemoryBundles"),
      ]);

      const rawChars = (charRes && Array.isArray(charRes.characters)) ? charRes.characters : [];
      ent.characters = _deduplicateCharacters(rawChars);

      // 장소: world_rules에서 scope가 location/region/area/place인 것
      const wrAll = (wrRes && Array.isArray(wrRes.items)) ? wrRes.items : [];
      ent.locations = wrAll.filter(r => r && isLocationWorldRuleScope(r.scope));

      // 물품: KG triple에서 소유/장비 술어 힌트
      const ITEM_PREDS = ["has","have","owns","own","carry","carries","held","holds","wield","equip","use","item","weapon","artifact","tool","inventory","소유","보유","장비","무기","아이템","획득"];
      const kgItems = (kgRes && Array.isArray(kgRes.items)) ? kgRes.items
                    : (kgRes && Array.isArray(kgRes.triples)) ? kgRes.triples : [];
      const itemMap = {};
      kgItems.forEach(tr => {
        if (!tr || typeof tr !== "object") return;
        const pred = (tr.predicate || "").toLowerCase();
        if (!ITEM_PREDS.some(h => pred.includes(h))) return;
        const obj = (tr.object || "").trim();
        if (!obj || itemMap[obj]) return;
        itemMap[obj] = { item: obj, owner: tr.subject || "", predicate: tr.predicate || "", source_turn: tr.source_turn, id: tr.id != null ? tr.id : null };
      });
      ent.items = Object.values(itemMap).slice(0, 40);
      ent.memoryBundles = bundleRes && Array.isArray(bundleRes.items) ? bundleRes.items : [];
      const availableMemoryBundleKeys = new Set(ent.memoryBundles.map((item) => explorerEntityMemoryBundleKey(item)).filter(Boolean));
      if (!(ent.forceMergeKeys instanceof Set)) ent.forceMergeKeys = new Set();
      ent.forceMergeKeys = new Set(Array.from(ent.forceMergeKeys).filter((key) => availableMemoryBundleKeys.has(key)));
      if (ent.memoryBundles.length > 0) {
        const selectedExists = ent.memoryBundles.some((item) => explorerEntityMemoryBundleKey(item) === ent.selectedMemoryBundleKey);
        if (!selectedExists) ent.selectedMemoryBundleKey = explorerEntityMemoryBundleKey(ent.memoryBundles[0]);
        ent.forceMergeKeys.delete(ent.selectedMemoryBundleKey);
        if (ent.activeSubTab === "memories") {
          await explorerFetchSelectedEntityMemoryItems();
        }
      } else {
        ent.selectedMemoryBundleKey = "";
        ent.memoryItems = [];
        ent.forceMergeKeys.clear();
      }
    } catch (e) {
      ent.error = String(e);
    }
    ent.loading = false;
  }

  function explorerFormatTemplate(template, values) {
    return String(template || "").replace(/\{([a-zA-Z0-9_]+)\}/g, function(_, key) {
      return values && Object.prototype.hasOwnProperty.call(values, key) ? String(values[key]) : "";
    });
  }

  function explorerEntityAliasRepairCandidateCount(result) {
    return Number(result && result.repairable_count || 0);
  }

  function renderExplorerEntityAliasRepairPanel() {
    const ent = _explorer.entities;
    const repair = ent.aliasRepair || { loading: false, applying: false, result: null, error: "" };
    const result = repair.result || null;
    const sid = explorerSessionId();
    const busy = !!(repair.loading || repair.applying);
    const repairable = explorerEntityAliasRepairCandidateCount(result);
    const summary = result
      ? explorerFormatTemplate(t('explorer.entities.aliasRepairSummary'), {
          scanned: Number(result.scanned || 0),
          groups: Number(result.alias_group_count || (Array.isArray(result.groups) ? result.groups.length : 0)),
          repairable,
          review: Number(result.review_required_count || 0),
          updated: Number(result.updated_count || 0),
        })
      : t('explorer.entities.aliasRepairNoResult');
    const status = busy
      ? (repair.applying ? t('explorer.entities.aliasRepairApplying') : t('explorer.entities.aliasRepairLoading'))
      : (repair.error ? t('explorer.entities.aliasRepairError') + ': ' + repair.error : summary);
    const groups = result && Array.isArray(result.groups) ? result.groups : [];
    const groupRows = groups.slice(0, 5).map((group) => {
      const canonical = formatDisplayEntityLabel(group.canonical_owner_name || group.canonical_owner_key || "");
      const aliases = Array.isArray(group.aliases) ? group.aliases.map((alias) => {
        const label = formatDisplayEntityLabel(alias.owner_entity_name || alias.owner_entity_key || "");
        const turns = Array.isArray(alias.source_turns) ? alias.source_turns.filter((turn) => Number.isFinite(Number(turn))).join('/') : '';
        return label + ' x' + Number(alias.count || 0) + (turns ? ' (turn ' + turns + ')' : '');
      }).join(', ') : '';
      const previews = Array.isArray(group.aliases) ? group.aliases.flatMap((alias) => Array.isArray(alias.memory_previews) ? alias.memory_previews : []).filter(Boolean).slice(0, 2).join(' / ') : '';
      const autoCount = Number(group.repairable_count || 0);
      const reviewCount = Number(group.review_required_count || 0);
      return '<div class="mo-ent-card" style="padding:8px;margin-top:8px">' +
        '<div class="mo-ent-card-header">' +
          '<span class="mo-ent-name">' + escapeAttr(t('explorer.entities.aliasRepairGroup')) + ': ' + escapeAttr(canonical) + '</span>' +
          '<span class="mo-tl-badge">' + escapeAttr(t('explorer.entities.aliasRepairAuto') + ' ' + autoCount + ' / ' + t('explorer.entities.aliasRepairReview') + ' ' + reviewCount) + '</span>' +
        '</div>' +
        '<div class="mo-ent-detail mo-note">' + escapeAttr(t('explorer.entities.aliasRepairAliases')) + ': ' + escapeAttr(aliases || '-') + '</div>' +
        (previews ? '<div class="mo-ent-detail mo-note">' + escapeAttr(t('explorer.entities.aliasRepairMemoryPreview')) + ': ' + escapeAttr(previews) + '</div>' : '') +
      '</div>';
    }).join('');
    const cleanNote = result && repairable <= 0
      ? '<div class="mo-note" style="margin-top:8px">' + escapeAttr(t('explorer.entities.aliasRepairClean')) + '</div>'
      : '';
    return '<div class="mo-settings-card mo-entity-memory-tool-card" style="margin:0;padding:10px;background:rgba(15,23,42,0.45)">' +
      '<div style="display:flex;align-items:flex-start;gap:10px;justify-content:space-between;flex-wrap:wrap">' +
        '<div style="min-width:180px;flex:1">' +
          '<div class="mo-section">' + escapeAttr(t('explorer.entities.aliasRepairTitle')) + '</div>' +
          '<div class="mo-section-desc">' + escapeAttr(t('explorer.entities.aliasRepairDesc')) + '</div>' +
        '</div>' +
        '<div style="display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end">' +
          '<button type="button" class="mo-btn" data-ent-alias-repair="dry-run"' + (!sid || busy ? ' disabled' : '') + '>' + escapeAttr(t('explorer.entities.aliasRepairDryRun')) + '</button>' +
          '<button type="button" class="mo-btn mo-btn-danger" data-ent-alias-repair="apply"' + (!sid || busy || repairable <= 0 ? ' disabled' : '') + '>' + escapeAttr(t('explorer.entities.aliasRepairApply')) + '</button>' +
        '</div>' +
      '</div>' +
      '<div class="mo-note" style="margin-top:8px">' + escapeAttr(status) + '</div>' +
      cleanNote +
      groupRows +
    '</div>';
  }

  async function explorerRunEntityAliasRepair(apply) {
    const sid = explorerSessionId();
    const ent = _explorer.entities;
    if (!sid) {
      ent.aliasRepair = { loading: false, applying: false, result: ent.aliasRepair && ent.aliasRepair.result || null, error: "세션 없음" };
      refreshExplorerUI();
      return;
    }
    const previous = ent.aliasRepair || { result: null };
    const candidateCount = explorerEntityAliasRepairCandidateCount(previous.result);
    if (apply) {
      if (candidateCount <= 0) return;
      const confirmMsg = explorerFormatTemplate(t('explorer.entities.aliasRepairConfirm'), { count: candidateCount });
      if (!confirm(confirmMsg)) return;
    }
    ent.aliasRepair = {
      loading: !apply,
      applying: !!apply,
      result: previous.result || null,
      error: "",
    };
    refreshExplorerUI();
    try {
      const result = await bridgeFetch("/subjective-entity-memories/alias-repair", {
        method: "POST",
        body: {
          source_chat_session_id: sid,
          apply: !!apply,
          limit: 1000,
        },
        timeoutMs: getRequestTimeoutSettingMs(),
      });
      if (!result || result.status !== "ok") {
        throw new Error(result && result.error ? String(result.error) : "alias repair failed");
      }
      ent.aliasRepair = { loading: false, applying: false, result, error: "" };
      if (apply && Number(result.updated_count || 0) > 0) {
        await explorerFetchEntities();
      }
    } catch (err) {
      ent.aliasRepair = {
        loading: false,
        applying: false,
        result: previous.result || null,
        error: err && err.message ? err.message : String(err),
      };
    }
    refreshExplorerUI();
  }

  function renderExplorerEntityForceMergePanel(selectedBundle) {
    const ent = _explorer.entities;
    if (!(ent.forceMergeKeys instanceof Set)) ent.forceMergeKeys = new Set();
    const selectedCount = ent.forceMergeKeys.size;
    const busy = !!ent.forceMergeLoading;
    const status = ent.forceMergeError
      ? t('explorer.entities.forceMergeError') + ': ' + ent.forceMergeError
      : (ent.forceMergeStatus || explorerFormatTemplate(t('explorer.entities.forceMergeStatus'), { count: selectedCount }));
    return '<div class="mo-settings-card mo-entity-memory-tool-card" style="margin:0;padding:10px;background:rgba(15,23,42,0.45)">' +
      '<div style="display:flex;align-items:flex-start;gap:10px;justify-content:space-between;flex-wrap:wrap">' +
        '<div style="min-width:180px;flex:1">' +
          '<div class="mo-section">' + escapeAttr(t('explorer.entities.forceMergeTitle')) + '</div>' +
          '<div class="mo-section-desc">' + escapeAttr(t('explorer.entities.forceMergeDesc')) + '</div>' +
          '<div class="mo-note" style="margin-top:8px">' + escapeAttr(status) + '</div>' +
        '</div>' +
        '<button type="button" class="mo-btn mo-btn-danger" data-ent-force-merge-apply' + (!selectedBundle || busy || selectedCount <= 0 ? ' disabled' : '') + '>' +
          escapeAttr(busy ? t('common.loading') : t('explorer.entities.forceMergeApply')) +
        '</button>' +
      '</div>' +
    '</div>';
  }

  async function explorerRunEntityForceMerge() {
    const sid = explorerSessionId();
    const ent = _explorer.entities;
    if (!(ent.forceMergeKeys instanceof Set)) ent.forceMergeKeys = new Set();
    const target = explorerSelectedEntityMemoryBundle();
    if (!sid || !target) {
      ent.forceMergeError = t('explorer.entities.forceMergeNeedTarget');
      refreshExplorerUI();
      return;
    }
    const selectedKeys = Array.from(ent.forceMergeKeys || []).filter(Boolean);
    if (selectedKeys.length <= 0) {
      ent.forceMergeError = t('explorer.entities.forceMergeNeedSelection');
      refreshExplorerUI();
      return;
    }
    const sourceOwnerKeys = selectedKeys.map((key) => String(key).split("\x1f")[0]).filter(Boolean);
    const targetLabel = formatDisplayEntityLabel(target.owner_entity_name || target.owner_entity_key || "");
    const confirmMsg = explorerFormatTemplate(t('explorer.entities.forceMergeConfirm'), {
      count: selectedKeys.length,
      target: targetLabel,
    });
    if (!confirm(confirmMsg)) return;
    ent.forceMergeLoading = true;
    ent.forceMergeError = "";
    ent.forceMergeStatus = "";
    refreshExplorerUI();
    try {
      const result = await bridgeFetch("/subjective-entity-memories/force-merge", {
        method: "POST",
        body: {
          source_chat_session_id: sid,
          target_owner_key: String(target.owner_entity_key || ""),
          target_owner_name: String(target.owner_entity_name || target.owner_entity_key || ""),
          target_owner_role: String(target.owner_entity_role || ""),
          target_visibility: String(target.owner_visibility || ""),
          source_owner_keys: Array.from(new Set(sourceOwnerKeys)),
          limit: 1000,
        },
        timeoutMs: getRequestTimeoutSettingMs(),
      });
      if (!result || result.status !== "ok") {
        throw new Error(result && result.error ? String(result.error) : "force merge failed");
      }
      ent.forceMergeKeys.clear();
      ent.forceMergeStatus = explorerFormatTemplate(t('explorer.entities.forceMergeDone'), {
        updated: Number(result.updated_count || 0),
      });
      await explorerFetchEntities();
      await explorerFetchSelectedEntityMemoryItems();
    } catch (err) {
      ent.forceMergeError = err && err.message ? err.message : String(err);
    }
    ent.forceMergeLoading = false;
    refreshExplorerUI();
  }

  // I-3c: Trust tab fetch — storylines + world-rules + hooks 동시 조회
  async function explorerFetchTrust() {
    const sid = explorerSessionId();
    const ts = _explorer.trust;
    if (!sid) { ts.storylines = []; ts.worldRules = []; ts.hooks = []; ts.error = "세션 없음"; return; }
    ts.loading = true; ts.error = null;
    try {
      const [slRes, wrRes, hkRes] = await Promise.all([
        safeCall(() => bridgeFetch("/storylines/" + encodeURIComponent(sid), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "trustFetchStorylines"),
        safeCall(() => bridgeFetch("/world-rules/" + encodeURIComponent(sid), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "trustFetchWorldRules"),
        safeCall(() => bridgeFetch("/pending-threads/" + encodeURIComponent(sid) + "?status=all", { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }), null, "trustFetchHooks"),
      ]);
      ts.storylines  = (slRes && Array.isArray(slRes.storylines))  ? slRes.storylines  : [];
      ts.worldRules  = (wrRes && Array.isArray(wrRes.items))       ? wrRes.items       : [];
      ts.hooks       = (hkRes && Array.isArray(hkRes.hooks))       ? hkRes.hooks       : [];
    } catch (e) {
      ts.error = String(e);
    }
    ts.loading = false;
  }

  // I-3c: Trust PATCH helper — PATCH /storylines/{id}/trust 등 호출
  async function explorerPatchTrust(model, id, field, value) {
    const sid = explorerSessionId();
    if (!sid) return;
    const key = model + "_" + id;
    _explorer.trust.patchStatus[key] = "saving";
    refreshExplorerUI();
    const urlMap = { storyline: "/storylines/", worldRule: "/world-rules/", hook: "/pending-threads/" };
    const path = (urlMap[model] || "/storylines/") + id + "/trust";
    const result = await safeCall(
      () => bridgeFetch(path, { method: "PATCH", body: { [field]: value }, timeoutMs: getRequestTimeoutSettingMs() }),
      null, "explorerPatchTrust"
    );
    if (result && result.status === "ok") {
      // 응답에서 최신 값 반영
      const listKey = model === "storyline" ? "storylines" : model === "worldRule" ? "worldRules" : "hooks";
      const arr = _explorer.trust[listKey];
      const idx = arr.findIndex(x => x.id === id);
      if (idx >= 0) {
        arr[idx].pinned         = !!result.pinned;
        arr[idx].suppressed     = !!result.suppressed;
        arr[idx].user_corrected = !!result.user_corrected;
      }
      _explorer.trust.patchStatus[key] = "ok";
    } else {
      _explorer.trust.patchStatus[key] = "error";
    }
    refreshExplorerUI();
  }

  // I-4d: World Graph — active scope fetch + inherited rules fetch
  async function explorerFetchWorldGraph() {
    const sid = explorerSessionId();
    const wg = _explorer.worldGraph;
    if (!sid) { wg.error = "세션 없음"; wg.rules = []; wg.allRules = []; return; }
    wg.loading = true; wg.error = null;
    refreshExplorerUI();
    try {
      // 1) 현재 active scope 조회
      const scopeResult = await safeCall(
        () => bridgeFetch("/session/" + encodeURIComponent(sid) + "/active-scope"),
        null, "explorerFetchWorldGraph/scope"
      );
      if (scopeResult && scopeResult.status === "ok") {
        wg.activeScope  = scopeResult.active_scope || "root";
        wg.scopeName    = scopeResult.scope_name || null;
        wg.pendingScope = wg.activeScope;
        // 저장된 scope의 name을 _scopeNames에 반영 (탭 재진입 시 올바른 값 복원)
        wg._scopeNames[wg.activeScope] = wg.scopeName;
      }
      // 2) inherited rules 조회 (저장된 scope 자동 사용)
      const rulesResult = await safeCall(
        () => bridgeFetch("/world-rules/" + encodeURIComponent(sid) + "/inherited"),
        null, "explorerFetchWorldGraph/rules"
      );
      if (rulesResult && rulesResult.status === "ok") {
        wg.rules      = rulesResult.rules || [];
        wg.scopeChain = rulesResult.scope_chain || [wg.activeScope];
      } else {
        wg.rules = [];
      }
      const allRulesResult = await safeCall(
        () => bridgeFetch("/world-rules/" + encodeURIComponent(sid), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }),
        null, "explorerFetchWorldGraph/allRules"
      );
      if (allRulesResult && Array.isArray(allRulesResult.items)) {
        const appliedIds = new Set((Array.isArray(wg.rules) ? wg.rules : []).map(r => Number(r.id)).filter(n => !Number.isNaN(n)));
        wg.allRules = allRulesResult.items.map(function(rule) {
          const item = Object.assign({}, rule);
          const id = Number(item.id);
          item.applied = appliedIds.has(id);
          item.inherited = !item.applied;
          return item;
        });
      } else {
        wg.allRules = (Array.isArray(wg.rules) ? wg.rules : []).map(function(rule) {
          const item = Object.assign({}, rule);
          item.applied = true;
          return item;
        });
      }
    } catch (err) {
      wg.error = err.message || "불러오기 실패";
    } finally {
      wg.loading = false;
      refreshExplorerUI();
    }
  }

  async function explorerSetWorldScope(scope, scopeName) {
    const sid = explorerSessionId();
    const wg = _explorer.worldGraph;
    if (!sid) return;
    wg.scopeSetStatus = "saving";
    refreshExplorerUI();
    const result = await safeCall(
      () => bridgeFetch(
        "/session/" + encodeURIComponent(sid) + "/active-scope",
        { method: "PATCH", body: { active_scope: scope, scope_name: scopeName || null }, timeoutMs: getRequestTimeoutSettingMs() }
      ),
      null, "explorerSetWorldScope"
    );
    if (result && result.status === "ok") {
      wg.activeScope  = result.active_scope;
      wg.scopeName    = result.scope_name || null;
      wg.scopeChain   = result.scope_chain || [wg.activeScope];
      wg.scopeSetStatus = "ok";
      // 저장 완료 → _scopeNames 갱신
      wg._scopeNames[wg.activeScope] = wg.scopeName;
      // rules 새로고침
      await explorerFetchWorldGraph();
    } else {
      wg.scopeSetStatus = "error";
      refreshExplorerUI();
    }
  }

  async function explorerChangeSession(sessionId) {
    _explorer.selectedSessionId = sessionId || null;
    _explorer.expandedItems.clear();
    await explorerLoadTab(_explorer.activeTab, true);
  }

  function explorerToggleExpand(type, id) {
    const key = type + "_" + id;
    if (_explorer.expandedItems.has(key)) {
      _explorer.expandedItems.delete(key);
    } else {
      _explorer.expandedItems.add(key);
    }
  }

  function explorerIsExpanded(type, id) {
    return _explorer.expandedItems.has(type + "_" + id);
  }

  function resetSessionRoutingRuntimeCaches() {
    _sessionCache = { charIdx: null, chatIdx: null, sessionId: null, observedChatUniqueId: "" };
    _sessionReadCompatCache = { cacheKey: "", plan: null, cachedAt: 0 };
    _sessionRoutingTurnBaselines.clear();
    _sessionMigrationApplyInFlight.clear();
    Object.keys(_sessionMigrationApplyLastAttemptAt).forEach(function(key) {
      delete _sessionMigrationApplyLastAttemptAt[key];
    });
  }

  function resetSessionMigrationStorageState() {
    _sessionMigrationAudit = {
      loaded: false,
      byPrimary: {},
      lastSavedAt: 0,
    };
    _sessionMigrationApply = {
      loaded: false,
      byPair: {},
      lastSavedAt: 0,
    };
  }

  async function getCurrentSessionRoutingCoordinates() {
    let chatIdx = null;
    let charIdx = null;
    if (R && typeof R.getCurrentChatIndex === "function") {
      try { chatIdx = await R.getCurrentChatIndex(); } catch { chatIdx = null; }
    }
    if (R && typeof R.getCurrentCharacterIndex === "function") {
      try { charIdx = await R.getCurrentCharacterIndex(); } catch { charIdx = null; }
    }
    return { charIdx, chatIdx };
  }

  function collectSessionRoutingCandidateIds(options = {}) {
    const out = [];
    const seen = new Set();
    addUniqueSessionId(out, seen, options.primarySessionId);
    addUniqueSessionId(out, seen, options.cachedSessionId);
    addUniqueSessionId(out, seen, options.pinnedSessionId);

    const charIdx = (typeof options.charIdx === "number" && Number.isFinite(options.charIdx)) ? options.charIdx : null;
    const chatIdx = (typeof options.chatIdx === "number" && Number.isFinite(options.chatIdx)) ? options.chatIdx : null;
    const chatUniqueId = String(options.chatUniqueId || "").trim();

    if (charIdx != null && chatUniqueId) addUniqueSessionId(out, seen, `char_${charIdx}_cid_${chatUniqueId}`);
    if (charIdx != null && chatIdx != null) addUniqueSessionId(out, seen, `char_${charIdx}_chat_${chatIdx}`);
    if (charIdx != null) addUniqueSessionId(out, seen, `char_${charIdx}`);
    if (chatIdx != null) addUniqueSessionId(out, seen, `chat_${chatIdx}`);
    return out;
  }

  function dropSessionMigrationAuditEntries(sessionIds) {
    const ids = Array.isArray(sessionIds)
      ? sessionIds.map(normalizeSessionId).filter(Boolean)
      : [];
    if (ids.length === 0) return 0;

    loadSessionMigrationAudit();
    let removed = 0;
    ids.forEach(function(sessionId) {
      if (_sessionMigrationAudit.byPrimary[sessionId]) {
        delete _sessionMigrationAudit.byPrimary[sessionId];
        removed += 1;
      }
    });

    if (removed > 0) {
      if (Object.keys(_sessionMigrationAudit.byPrimary).length === 0) {
        safeStorageRemove(SESSION_MIGRATION_AUDIT_KEY);
      } else {
        saveSessionMigrationAudit(true);
      }
    }
    return removed;
  }

  function dropSessionMigrationApplyEntries(sessionIds) {
    const ids = new Set(Array.isArray(sessionIds)
      ? sessionIds.map(normalizeSessionId).filter(Boolean)
      : []);
    if (ids.size === 0) return 0;

    loadSessionMigrationApplyState();
    let removed = 0;
    Object.keys(_sessionMigrationApply.byPair || {}).forEach(function(key) {
      const row = _sessionMigrationApply.byPair[key] || {};
      const primary = normalizeSessionId(row.primarySessionId || "");
      const alias = normalizeSessionId(row.aliasSessionId || "");
      if (ids.has(primary) || ids.has(alias)) {
        delete _sessionMigrationApply.byPair[key];
        removed += 1;
      }
    });

    if (removed > 0) {
      if (Object.keys(_sessionMigrationApply.byPair).length === 0) {
        safeStorageRemove(SESSION_MIGRATION_APPLY_KEY);
      } else {
        saveSessionMigrationApplyState(true);
      }
    }
    return removed;
  }

  function formatSessionRoutingTargetLine(sessionIds) {
    const items = Array.isArray(sessionIds) ? sessionIds.filter(Boolean) : [];
    if (items.length === 0) return SESSION_FALLBACK;
    return items.slice(0, 4).join("\n") + (items.length > 4 ? `\n... (+${items.length - 4})` : "");
  }

  let _sessionRoutingResetState = { loading: false, error: null };

  async function resetSessionRoutingState(selectedSessionId) {
    const sessionId = normalizeSessionId(selectedSessionId);
    if (!sessionId) {
      alert(t('routing.resetState.noSession'));
      return false;
    }
    if (_sessionRoutingResetState.loading) return false;

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    const confirmed = await showConfirmModal(
      t('routing.resetState.title'),
      t('routing.resetState.confirmTarget') + " " + shortId + "\n\n" +
      t('routing.resetState.confirmDesc') + "\n\n" +
      t('common.confirmContinue')
    );
    if (!confirmed) return false;

    _sessionRoutingResetState.loading = true;
    _sessionRoutingResetState.error = null;
    refreshExplorerUI();

    try {
      const coords = await getCurrentSessionRoutingCoordinates();
      const activeIdentity = await getActiveChatSessionIdentity(coords.charIdx, coords.chatIdx);
      const pinnedRecord = await loadPinnedSessionId(coords.charIdx, coords.chatIdx);
      const candidateIds = collectSessionRoutingCandidateIds({
        primarySessionId: sessionId,
        cachedSessionId: _sessionCache.sessionId,
        pinnedSessionId: pinnedRecord && pinnedRecord.sessionId,
        charIdx: coords.charIdx,
        chatIdx: coords.chatIdx,
        chatUniqueId: activeIdentity.chatUniqueId,
      });

      if (coords.charIdx != null && coords.chatIdx != null && candidateIds.indexOf(sessionId) >= 0) {
        await persistentDelete(makeSessionPinKey(coords.charIdx, coords.chatIdx));
      }

      safeStorageRemove(SESSION_MIGRATION_AUDIT_KEY);
      safeStorageRemove(SESSION_MIGRATION_APPLY_KEY);
      resetSessionMigrationStorageState();
      resetSessionRoutingRuntimeCaches();

      _sessionRoutingResetState.loading = false;
      refreshExplorerUI();
      alert(t('routing.resetState.success'));
      return true;
    } catch (err) {
      _sessionRoutingResetState.loading = false;
      _sessionRoutingResetState.error = err.message || t('common.unknownError');
      refreshExplorerUI();
      alert(t('routing.resetState.failed') + ": " + _sessionRoutingResetState.error);
      return false;
    }
  }

  async function hardResetCurrentSessionMapping() {
    const coords = await getCurrentSessionRoutingCoordinates();
    const activeIdentity = await getActiveChatSessionIdentity(coords.charIdx, coords.chatIdx);
    const pinnedRecord = await loadPinnedSessionId(coords.charIdx, coords.chatIdx);
    const candidateIds = collectSessionRoutingCandidateIds({
      cachedSessionId: _sessionCache.sessionId,
      pinnedSessionId: pinnedRecord && pinnedRecord.sessionId,
      charIdx: coords.charIdx,
      chatIdx: coords.chatIdx,
      chatUniqueId: activeIdentity.chatUniqueId,
    });

    if ((coords.charIdx == null && coords.chatIdx == null) && candidateIds.length === 0) {
      alert(t('routing.hardReset.unavailable'));
      return false;
    }

    const confirmed = await showConfirmModal(
      t('routing.hardReset.title'),
      t('routing.hardReset.confirmTarget') + "\n" + formatSessionRoutingTargetLine(candidateIds) + "\n\n" +
      t('routing.hardReset.confirmDesc') + "\n\n" +
      t('common.confirmContinue')
    );
    if (!confirmed) return false;

    try {
      if (coords.charIdx != null && coords.chatIdx != null) {
        await persistentDelete(makeSessionPinKey(coords.charIdx, coords.chatIdx));
      }
      dropSessionMigrationAuditEntries(candidateIds);
      dropSessionMigrationApplyEntries(candidateIds);
      resetSessionRoutingRuntimeCaches();
      alert(t('routing.hardReset.success'));
      return true;
    } catch (err) {
      alert(t('routing.hardReset.failed') + ": " + (err.message || t('common.unknownError')));
      return false;
    }
  }

  function resetArchiveDatabaseUICaches() {
    try {
      _explorer.sessions = [];
      _explorer.items = [];
      _explorer.total = 0;
      _explorer.error = "";
    } catch { /* no-op */ }
    try {
      _timelineState.sessions = [];
      _timelineState.items = [];
      _timelineState.pendingItems = [];
      _timelineState.meta = null;
      _timelineState.hasMore = false;
      _timelineState.nextBeforeTurn = 0;
      _timelineState.selectedSessionId = "";
      _timelineState.sessionId = "";
      _timelineState.detailItem = null;
      _timelineState.detailError = "";
      _timelineSelectedDetail = null;
    } catch { /* no-op */ }
    try {
      refreshTimelineUI();
      refreshExplorerUI();
    } catch { /* no-op */ }
  }

  async function resetArchiveDatabaseFromDebugUI() {
    const phrase = t("databaseReset.confirmPhrase");
    const confirmed = await showConfirmModal(
      t("databaseReset.title"),
      t("databaseReset.confirmDesc") + "\n\n" +
      tf("databaseReset.prompt", { phrase }) + "\n\n" +
      t("common.confirmContinue")
    );
    if (!confirmed) return false;
    const typed = (typeof prompt === "function")
      ? prompt(tf("databaseReset.prompt", { phrase }), "")
      : "";
    if (String(typed || "").trim() !== phrase) {
      alert(t("databaseReset.cancelled"));
      return false;
    }
    const data = await bridgeFetch("/admin/database-reset", {
      method: "POST",
      body: {
        debug: true,
        confirm: "RESET_ARCHIVE_CENTER_DB",
        reset_vector: true,
      },
      timeoutMs: 90000,
    });
    if (!data || data.status !== "ok") {
      alert(t("databaseReset.failed"));
      return false;
    }
    resetArchiveDatabaseUICaches();
    alert(tf("databaseReset.success", {
      tables: data.tables_cleared || 0,
      rows: data.rows_deleted || 0,
      vector: data.vector_reset_status || "unknown",
    }));
    return true;
  }

  // ──────────────────────────────────────────────────────────────
  // [SESSION EXPORT — Sprint 3-C-2]
  // ──────────────────────────────────────────────────────────────

  let _exportState = { loading: false, error: null };

  async function exportSession(sessionId) {
    if (!sessionId) {
      alert(t('export.noSession'));
      return;
    }
    if (_exportState.loading) return;

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    const confirmed = await showConfirmModal("Session Export",
      "[Session Export]\n\n" +
      t('export.confirmTarget') + " " + shortId + "\n\n" +
      t('export.confirmDesc') + "\n\n" + t('common.confirmContinue')
    );
    if (!confirmed) return;

    _exportState.loading = true;
    _exportState.error = null;
    refreshExplorerUI();

    try {
      const encodedSid = encodeURIComponent(sessionId);
      const result = await safeCall(
        () => bridgeFetch("/sessions/" + encodedSid + "/export"),
        null, "exportSession"
      );

      _exportState.loading = false;

      if (!result || result.status !== "ok") {
        _exportState.error = (result && result.detail) ? result.detail : t('export.failed');
        refreshExplorerUI();
        alert("Export " + t('common.failed') + ": " + _exportState.error);
        return;
      }

      // export 성공 — modal 표시
      showExportModal(result);

    } catch (err) {
      _exportState.loading = false;
      _exportState.error = err.message || t('common.unknownError');
      refreshExplorerUI();
      alert("Export " + t('common.error') + ": " + _exportState.error);
    }
  }

  function showConfirmModal(title, message) {
    const existing = document.getElementById("mo-confirm-modal");
    if (existing) existing.remove();

    const safeTitle = escapeAttr(title || "Confirm");
    const messageHtml = String(message || "")
      .split("\n")
      .map(line => escapeAttr(line))
      .join("<br>");

    return new Promise((resolve) => {
      let settled = false;
      const modal = document.createElement("div");
      modal.id = "mo-confirm-modal";
      modal.className = "mo-export-overlay";
      modal.innerHTML =
        '<div class="mo-export-panel" style="width:min(92%,560px);max-height:none">' +
          '<div class="mo-export-hdr">' +
            '<h3>' + safeTitle + '</h3>' +
            '<button class="mo-close" id="mo-confirm-close-btn">✕</button>' +
          '</div>' +
          '<div class="mo-export-info" style="white-space:normal;line-height:1.6">' + messageHtml + '</div>' +
          '<div class="mo-export-actions" style="justify-content:flex-end">' +
            '<button class="mo-btn mo-btn-ghost" id="mo-confirm-cancel-btn">' + t('explorer.edit.cancelBtn') + '</button>' +
            '<button class="mo-btn mo-btn-primary" id="mo-confirm-ok-btn">OK</button>' +
          '</div>' +
        '</div>';

      const finish = (value) => {
        if (settled) return;
        settled = true;
        modal.remove();
        resolve(!!value);
      };

      document.body.appendChild(modal);
      const panel = modal.querySelector(".mo-export-panel");
      if (panel) panel.addEventListener("click", (event) => event.stopPropagation());
      modal.addEventListener("click", () => finish(false));
      document.getElementById("mo-confirm-close-btn").addEventListener("click", () => finish(false));
      document.getElementById("mo-confirm-cancel-btn").addEventListener("click", () => finish(false));
      document.getElementById("mo-confirm-ok-btn").addEventListener("click", () => finish(true));
    });
  }

  function showExportModal(exportData) {
    // 기존 모달 제거
    const existing = document.getElementById("mo-export-modal");
    if (existing) existing.remove();

    const jsonStr = JSON.stringify(exportData, null, 2);
    const summary = exportData.summary || {};
    const sid = exportData.chat_session_id || "?";
    const shortSid = sid.length > 35 ? sid.slice(0, 15) + "…" + sid.slice(-10) : sid;

    const modal = document.createElement("div");
    modal.id = "mo-export-modal";
    modal.className = "mo-export-overlay";
    modal.innerHTML =
      '<div class="mo-export-panel">' +
        '<div class="mo-export-hdr">' +
          '<h3>📦 Session Export</h3>' +
          '<button class="mo-close" id="mo-export-close-btn">✕</button>' +
        '</div>' +
        '<div class="mo-export-info">' +
          '<div><strong>Session:</strong> ' + escapeAttr(shortSid) + '</div>' +
          '<div><strong>Exported:</strong> ' + escapeAttr(exportData.exported_at || "?") + '</div>' +
          '<div><strong>Chat Logs:</strong> ' + (summary.chat_logs_count ?? 0) +
            ' · <strong>Memories:</strong> ' + (summary.memories_count ?? 0) +
            ' · <strong>KG Triples:</strong> ' + (summary.kg_triples_count ?? 0) +
          '</div>' +
        '</div>' +
        '<div class="mo-export-actions">' +
          '<button class="mo-btn mo-btn-primary" id="mo-export-download-btn">' + t('export.downloadBtn') + '</button>' +
          '<button class="mo-btn mo-btn-info" id="mo-export-copy-btn">' + t('export.copyBtn') + '</button>' +
        '</div>' +
        '<div class="mo-export-json-wrap">' +
          '<textarea class="mo-export-json" id="mo-export-json-textarea" readonly>' + escapeAttr(jsonStr) + '</textarea>' +
        '</div>' +
      '</div>';

    document.body.appendChild(modal);

    // 이벤트 연결
    document.getElementById("mo-export-close-btn").addEventListener("click", () => modal.remove());
    modal.addEventListener("click", (e) => { if (e.target === modal) modal.remove(); });

    document.getElementById("mo-export-download-btn").addEventListener("click", () => {
      try {
        const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: "application/json" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        const ts = (exportData.exported_at || new Date().toISOString()).replace(/[:.]/g, "-").slice(0, 19);
        const safeSid = (sid || "session").replace(/[^a-zA-Z0-9_-]/g, "_").slice(0, 40);
        a.href = url;
        a.download = "session_export_" + safeSid + "_" + ts + ".json";
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      } catch (err) {
        alert(t('export.downloadFailed') + ": " + (err.message || "unknown"));
      }
    });

    document.getElementById("mo-export-copy-btn").addEventListener("click", () => {
      try {
        const textarea = document.getElementById("mo-export-json-textarea");
        if (textarea) {
          textarea.select();
          document.execCommand("copy");
          const btn = document.getElementById("mo-export-copy-btn");
          if (btn) { btn.textContent = t('export.copied'); setTimeout(() => { btn.textContent = t('export.copyBtn'); }, 2000); }
        }
      } catch {
        alert(t('export.copyFailed'));
      }
    });
  }

  // ──────────────────────────────────────────────────────────────
  // [REINDEX BATCH — Sprint 3-D]
  // ──────────────────────────────────────────────────────────────

  let _reindexState = { loading: false, error: null, result: null, job: null };
  const _adminJobPollTimers = {};

  function clearAdminJobPollTimer(kind) {
    const key = String(kind || "job");
    if (_adminJobPollTimers[key]) {
      clearTimeout(_adminJobPollTimers[key]);
      delete _adminJobPollTimers[key];
    }
  }

  function adminJobProgressValue(progress, keys, fallback) {
    const p = progress && typeof progress === "object" ? progress : {};
    for (const key of keys) {
      if (p[key] != null && p[key] !== "") return p[key];
    }
    return fallback;
  }

  function renderAdminJobProgressHtml(job, label) {
    if (!job || typeof job !== "object") return "";
    const progress = job.progress && typeof job.progress === "object" ? job.progress : {};
    const status = String(job.status || progress.status || "running");
    const stage = String(progress.stage || "running");
    const pct = Math.max(0, Math.min(100, Number(progress.progress_percent || 0)));
    const processed = Number(adminJobProgressValue(progress, ["processed", "processed_count"], 0) || 0);
    const total = Number(adminJobProgressValue(progress, ["candidate_count", "total_candidates", "total"], 0) || 0);
    const succeeded = Number(adminJobProgressValue(progress, ["succeeded", "upserted", "saved"], 0) || 0);
    const failed = Number(adminJobProgressValue(progress, ["failed_count", "failed"], 0) || 0);
    const skipped = Number(adminJobProgressValue(progress, ["skipped_count", "skipped"], 0) || 0);
    const failedTurns = Array.isArray(progress.failed_turns) ? progress.failed_turns : [];
    const failedIds = Array.isArray(progress.failed_ids) ? progress.failed_ids : [];
    const last = progress.last_processed != null ? String(progress.last_processed) : "";
    const phase = progress.phase != null ? String(progress.phase) : "";
    const reason = progress.reason != null ? String(progress.reason) : "";
    const action = progress.ui_action != null ? String(progress.ui_action) : "";
    const failurePreview = failedTurns.length > 0
      ? failedTurns.slice(0, 5).map(function(item) {
          if (!item || typeof item !== "object") return String(item || "");
          return "#" + String(item.turn_index || "?") + ":" + String(item.reason || item.error || "failed");
        }).join(", ")
      : (failedIds.length > 0 ? "ids " + failedIds.slice(0, 8).join(", ") : "");
    let html = '<div class="mo-reindex-result">' +
      '<strong>' + escapeAttr(label || "Background Job") + '</strong> ' + escapeAttr(status) +
      '<br>job: ' + escapeAttr(String(job.job_id || "")) +
      '<br>stage: ' + escapeAttr(stage) +
      (phase ? ' / phase: ' + escapeAttr(phase) : '') +
      ' / progress: ' + pct + '% (' + processed + '/' + total + ')' +
      ' / ok: ' + succeeded + ' / failed: ' + failed + ' / skipped: ' + skipped +
      (last ? '<br>last: ' + escapeAttr(last) : '') +
      '<div style="height:6px;background:#172033;border-radius:999px;margin-top:6px;overflow:hidden">' +
        '<div style="height:6px;width:' + pct + '%;background:#68a7ff;border-radius:999px"></div>' +
      '</div>' +
      '<span style="font-size:11px;color:#888">Runs in backend background; browser request timeout no longer stops the job.</span>';
    if (failurePreview) {
      html += '<br><span style="font-size:11px;color:#f59e0b">failures: ' + escapeAttr(failurePreview) + '</span>';
    }
    if (reason) {
      html += '<br><span style="font-size:11px;color:#f59e0b">reason: ' + escapeAttr(reason) + '</span>';
    }
    if (action) {
      html += '<br><span style="font-size:11px;color:#93c5fd">action: ' + escapeAttr(action) + '</span>';
    }
    if (progress.error) {
      html += '<br><span style="font-size:11px;color:#f87171">error: ' + escapeAttr(String(progress.error)) + '</span>';
    }
    html += '</div>';
    return html;
  }

  function acceptAdminBackgroundJob(kind, state, result) {
    if (!result || !result.job_id) return false;
    const key = String(kind || "job");
    clearAdminJobPollTimer(key);
    state.loading = true;
    state.error = null;
    state.result = null;
    state.job = result;
    pollAdminBackgroundJob(key, state, result.job_id);
    return true;
  }

  async function pollAdminBackgroundJob(kind, state, jobId) {
    const key = String(kind || "job");
    clearAdminJobPollTimer(key);
    if (!jobId) return;
    try {
      const job = await safeCall(
        () => bridgeFetch("/admin/jobs/" + encodeURIComponent(jobId), {
          method: "GET",
          timeoutMs: Math.min(8000, getRequestTimeoutSettingMs()),
        }),
        null, "pollAdminBackgroundJob"
      );
      if (!job || job.status === "not_found") {
        state.loading = false;
        state.error = "background job not found: " + jobId;
        refreshExplorerUI({ preserveScroll: true });
        return;
      }
      state.job = job;
      const status = String(job.status || "");
      if (status === "completed") {
        state.loading = false;
        state.result = job.result || job;
        refreshExplorerUI({ preserveScroll: true });
        return;
      }
      if (status === "failed" || status === "cancelled" || status === "canceled") {
        state.loading = false;
        state.result = job.result || null;
        state.error = String(job.error || (job.progress && job.progress.error) || "background job failed");
        refreshExplorerUI({ preserveScroll: true });
        return;
      }
      refreshExplorerUI({ preserveScroll: true });
      _adminJobPollTimers[key] = setTimeout(function() {
        pollAdminBackgroundJob(key, state, jobId);
      }, 1200);
    } catch (err) {
      state.loading = false;
      state.error = err && err.message ? err.message : "background job poll failed";
      refreshExplorerUI({ preserveScroll: true });
    }
  }

  async function reindexSession(sessionId, force, batchSize, maxItems) {
    if (!sessionId) {
      alert(t('reindex.noSession'));
      return;
    }
    if (_reindexState.loading) return;

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    const confirmed = await showConfirmModal("Reindex Batch",
      "[Reindex Batch]\n\n" +
      t('reindex.confirmTarget') + " " + shortId + "\n" +
      "force: " + (force ? "YES" : "NO") + "\n" +
      "batch_size: " + batchSize + ", max_items: " + maxItems + "\n\n" +
      t('reindex.confirmDesc') + "\n" + t('common.confirmContinue')
    );
    if (!confirmed) return;

    _reindexState.loading = true;
    _reindexState.error = null;
    _reindexState.result = null;
    _reindexState.job = null;
    refreshExplorerUI();

    try {
      const result = await safeCall(
        () => bridgeFetch("/admin/reindex", {
          method: "POST",
          body: {
            chat_session_id: sessionId,
            force: !!force,
            batch_size: parseInt(batchSize) || 20,
            max_items: parseInt(maxItems) || 200,
            background: true,
            client_meta: buildAdminRuntimeClientMeta({ source: "explorer_reindex" }),
          },
        }),
        null, "reindexSession"
      );

      if (acceptAdminBackgroundJob("reindex", _reindexState, result)) {
        refreshExplorerUI({ preserveScroll: true });
        return;
      }

      _reindexState.loading = false;

      if (!result || result.status !== "ok") {
        _reindexState.error = (result && result.detail) ? result.detail : t('reindex.failed');
        refreshExplorerUI();
        return;
      }

      _reindexState.result = result;
      refreshExplorerUI();

    } catch (err) {
      _reindexState.loading = false;
      _reindexState.error = err.message || t('common.unknownError');
      refreshExplorerUI();
    }
  }

  // ──────────────────────────────────────────────────────────────
  // [RESCAN — Sprint 3-D-2]
  // ──────────────────────────────────────────────────────────────

  let _rescanState = { loading: false, error: null, result: null, job: null };
  let _sessionNormalizeState = { loading: false, error: null, result: null, job: null, planWarning: "" };
  let _activeChatRescanDryRunState = { loading: false, error: null, result: null };
  let _activeChatRecentRebuildState = { loading: false, error: null, result: null };
  let _chatLogRepairState = { loading: false, error: null, progress: null, result: null };

  function setChatLogRepairProgress(kind, detail) {
    _chatLogRepairState.progress = {
      kind: String(kind || "info"),
      detail: String(detail || "").trim(),
      updated_at: new Date().toISOString(),
    };
  }

  function normalizeTurnIndexList(turnIndices) {
    const seen = new Set();
    const normalized = [];
    for (const rawTurn of Array.isArray(turnIndices) ? turnIndices : []) {
      const turnIndex = parseInt(rawTurn, 10);
      if (isNaN(turnIndex) || turnIndex < 0 || seen.has(turnIndex)) continue;
      seen.add(turnIndex);
      normalized.push(turnIndex);
    }
    normalized.sort((left, right) => left - right);
    return normalized;
  }

  function formatTurnIndexPreview(turnIndices, maxItems = 8) {
    const turns = normalizeTurnIndexList(turnIndices);
    if (turns.length === 0) return "-";
    if (turns.length <= maxItems) return turns.join(", ");
    const headCount = Math.max(2, maxItems - 2);
    return turns.slice(0, headCount).join(", ") + " ... " + turns[turns.length - 1];
  }

  function formatHierarchyBlockedPreview(layer, maxItems = 5) {
    const blocked = layer && Array.isArray(layer.blocked) ? layer.blocked : [];
    if (blocked.length === 0) return "";
    const rows = blocked.slice(0, maxItems).map(function(item) {
      const fromTurn = Number(item && item.from_turn || 0);
      const toTurn = Number(item && item.to_turn || 0);
      const range = fromTurn > 0 && toTurn > 0 ? ("#" + fromTurn + "-" + toTurn) : "#?";
      return range + ":" + String(item && item.reason || "blocked");
    });
    if (blocked.length > maxItems) rows.push("+" + String(blocked.length - maxItems) + " more");
    return rows.join(" / ");
  }

  function formatHierarchyBlockedSummary(hierarchyBackfill) {
    const hb = hierarchyBackfill && typeof hierarchyBackfill === "object" ? hierarchyBackfill : null;
    if (!hb) return "";
    const layerRows = [
      ["chapter", hb.chapter],
      ["arc", hb.arc],
      ["saga", hb.saga],
    ].map(function(row) {
      const layer = row[1] && typeof row[1] === "object" ? row[1] : null;
      const blocked = layer && Array.isArray(layer.blocked) ? layer.blocked.length : 0;
      const preview = formatHierarchyBlockedPreview(layer, 4);
      if (blocked <= 0 && !preview) return "";
      return row[0] + " blocked " + blocked + (preview ? " (" + preview + ")" : "");
    }).filter(Boolean);
    return layerRows.join(" / ");
  }

  function sanitizeChatLogRepairEntry(entry, fallbackSource) {
    if (!entry || typeof entry !== "object") return null;
    const turnIndex = parseInt(entry.turn_index, 10);
    if (isNaN(turnIndex) || turnIndex < 1) return null;
    const userContent = String(entry.user_content || "");
    const assistantContent = String(entry.assistant_content || "");
    if (!userContent && !assistantContent) return null;
    return {
      turn_index: turnIndex,
      user_content: userContent,
      assistant_content: assistantContent,
      created_at: String(entry.created_at || ""),
      source: String(entry.source || fallbackSource || "local"),
    };
  }

  function readChatLogRestoreSnapshotStore() {
    try {
      const raw = safeStorageGet(CHATLOG_RESTORE_SNAPSHOT_STORAGE_KEY);
      if (!raw) return {};
      const parsed = JSON.parse(raw);
      return parsed && typeof parsed === "object" ? parsed : {};
    } catch {
      return {};
    }
  }

  function writeChatLogRestoreSnapshotStore(store) {
    try {
      const normalizedStore = store && typeof store === "object" ? store : {};
      if (Object.keys(normalizedStore).length === 0) {
        safeStorageRemove(CHATLOG_RESTORE_SNAPSHOT_STORAGE_KEY);
        persistentDelete(CHATLOG_RESTORE_SNAPSHOT_STORAGE_KEY).catch(() => {});
        return;
      }
      const raw = JSON.stringify(normalizedStore);
      safeStorageSet(CHATLOG_RESTORE_SNAPSHOT_STORAGE_KEY, raw);
      persistentSet(CHATLOG_RESTORE_SNAPSHOT_STORAGE_KEY, raw).catch(() => {});
    } catch { /* silent */ }
  }

  function getChatLogRestoreSnapshotEntries(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) return [];
    const store = readChatLogRestoreSnapshotStore();
    const entries = Array.isArray(store[sid]) ? store[sid] : [];
    return entries
      .map(entry => sanitizeChatLogRepairEntry(entry, "delete_snapshot"))
      .filter(Boolean)
      .sort((left, right) => left.turn_index - right.turn_index);
  }

  function saveChatLogRestoreSnapshotEntries(sessionId, entries) {
    const sid = String(sessionId || "").trim();
    if (!sid) return;

    const store = readChatLogRestoreSnapshotStore();
    const merged = new Map();
    const existingEntries = Array.isArray(store[sid]) ? store[sid] : [];
    for (const rawEntry of existingEntries.concat(Array.isArray(entries) ? entries : [])) {
      const entry = sanitizeChatLogRepairEntry(rawEntry, "delete_snapshot");
      if (!entry) continue;
      const current = merged.get(entry.turn_index) || {
        turn_index: entry.turn_index,
        user_content: "",
        assistant_content: "",
        created_at: "",
        source: entry.source || "delete_snapshot",
      };
      if (!current.user_content && entry.user_content) current.user_content = entry.user_content;
      if (!current.assistant_content && entry.assistant_content) current.assistant_content = entry.assistant_content;
      if (!current.created_at && entry.created_at) current.created_at = entry.created_at;
      if (current.source.indexOf(entry.source) === -1) current.source += "+" + entry.source;
      merged.set(entry.turn_index, current);
    }

    const serialized = Array.from(merged.values()).sort((left, right) => left.turn_index - right.turn_index);
    if (serialized.length === 0) delete store[sid];
    else store[sid] = serialized;
    writeChatLogRestoreSnapshotStore(store);
  }

  function clearChatLogRestoreSnapshotEntries(sessionId, turnIndices) {
    const sid = String(sessionId || "").trim();
    if (!sid) return;
    const turns = new Set(normalizeTurnIndexList(turnIndices));
    if (turns.size === 0) return;

    const store = readChatLogRestoreSnapshotStore();
    const existingEntries = Array.isArray(store[sid]) ? store[sid] : [];
    const nextEntries = existingEntries
      .map(entry => sanitizeChatLogRepairEntry(entry, "delete_snapshot"))
      .filter(entry => entry && !turns.has(entry.turn_index));

    if (nextEntries.length === 0) delete store[sid];
    else store[sid] = nextEntries;
    writeChatLogRestoreSnapshotStore(store);
  }

  function getChatLogRepairJournalEntries(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) return [];

    const merged = new Map();
    for (const item of _failedQueue) {
      if (!item || item.type !== "save" || !item.payload) continue;
      if (String(item.payload.chat_session_id || "").trim() !== sid) continue;
      const entry = sanitizeChatLogRepairEntry(item.payload, "failed_queue");
      if (!entry) continue;
      const current = merged.get(entry.turn_index) || {
        turn_index: entry.turn_index,
        user_content: "",
        assistant_content: "",
        created_at: entry.created_at || item.addedAt || "",
        source: "failed_queue",
      };
      if (!current.user_content && entry.user_content) current.user_content = entry.user_content;
      if (!current.assistant_content && entry.assistant_content) current.assistant_content = entry.assistant_content;
      merged.set(entry.turn_index, current);
    }

    return Array.from(merged.values()).sort((left, right) => left.turn_index - right.turn_index);
  }

  async function removeFailedQueueItemsByTurn(sessionId, turnIndices, itemType = "save") {
    const sid = String(sessionId || "").trim();
    const turns = new Set(normalizeTurnIndexList(turnIndices));
    if (!sid || turns.size === 0) return;

    let changed = false;
    for (let index = _failedQueue.length - 1; index >= 0; index--) {
      const item = _failedQueue[index];
      const itemTurnIndex = parseInt(item && item.payload && item.payload.turn_index, 10);
      const itemSessionId = String(item && item.payload && item.payload.chat_session_id || "").trim();
      if (!item || item.type !== itemType || itemSessionId !== sid || isNaN(itemTurnIndex) || !turns.has(itemTurnIndex)) continue;
      _failedQueue.splice(index, 1);
      changed = true;
    }
    if (changed) {
      await saveFailedQueueToStorage();
    }
  }

  function buildChatLogRepairReplayCandidateBundle(sessionId) {
    const journalEntries = getChatLogRepairJournalEntries(sessionId);
    const snapshotEntries = getChatLogRestoreSnapshotEntries(sessionId);
    const merged = new Map();

    function absorbEntries(entries, sourceType) {
      for (const rawEntry of entries) {
        const entry = sanitizeChatLogRepairEntry(rawEntry, sourceType);
        if (!entry) continue;
        const current = merged.get(entry.turn_index) || {
          turn_index: entry.turn_index,
          user_content: "",
          assistant_content: "",
          created_at: "",
          source: sourceType,
        };
        if (!current.user_content && entry.user_content) current.user_content = entry.user_content;
        if (!current.assistant_content && entry.assistant_content) current.assistant_content = entry.assistant_content;
        if (!current.created_at && entry.created_at) current.created_at = entry.created_at;
        if (current.source.indexOf(sourceType) === -1) current.source += "+" + sourceType;
        merged.set(entry.turn_index, current);
      }
    }

    absorbEntries(journalEntries, "failed_queue");
    absorbEntries(snapshotEntries, "delete_snapshot");

    const entries = Array.from(merged.values()).sort((left, right) => left.turn_index - right.turn_index);
    return {
      entries,
      journalCount: journalEntries.length,
      deletedSnapshotCount: snapshotEntries.length,
      candidateTurnIndices: entries.map(entry => entry.turn_index),
    };
  }

  async function explorerFetchAllChatLogsForSession(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) return [];

    const items = [];
    const pageSize = 200;
    let offset = 0;
    let loopGuard = 0;

    while (loopGuard < ACTIVE_CHAT_RESCAN_DRY_RUN_CHATLOG_PAGE_LIMIT) {
      const params = new URLSearchParams();
      params.set("chat_session_id", sid);
      params.set("limit", String(pageSize));
      params.set("offset", String(offset));
      const result = await safeCall(
        () => bridgeFetch("/explorer/chat_logs?" + params.toString()),
        null,
        "explorerFetchAllChatLogsForSession"
      );
      if (!result || !Array.isArray(result.items) || result.items.length === 0) break;
      items.push(...result.items);
      if (!result.has_more) break;
      offset = items.length;
      loopGuard += 1;
    }

    return items;
  }

  async function explorerFetchTimelineItemsForSessionDryRun(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) return { items: [], limited: false };

    const items = [];
    let beforeTurn = 0;
    let loopGuard = 0;
    let limited = false;

    while (loopGuard < ACTIVE_CHAT_RESCAN_DRY_RUN_TIMELINE_PAGE_LIMIT) {
      const params = new URLSearchParams();
      params.set("sessionId", sid);
      params.set("limit", "200");
      if (beforeTurn > 0) params.set("beforeTurn", String(beforeTurn));
      const result = await safeCall(
        () => bridgeFetch("/timeline?" + params.toString(), { method: "GET", timeoutMs: getRequestTimeoutSettingMs() }),
        null,
        "explorerFetchTimelineItemsForSessionDryRun"
      );
      if (!result || result.status !== "ok" || !Array.isArray(result.items) || result.items.length === 0) break;
      items.push(...result.items);
      const nextBeforeTurn = Number((result.meta || {}).next_before_turn || 0);
      if (!nextBeforeTurn || nextBeforeTurn <= 0) break;
      beforeTurn = nextBeforeTurn;
      loopGuard += 1;
    }

    if (loopGuard >= ACTIVE_CHAT_RESCAN_DRY_RUN_TIMELINE_PAGE_LIMIT) {
      limited = true;
    }
    return { items, limited };
  }

  function normalizeActiveChatRescanCompareText(text) {
    return String(text || "").replace(/\s+/g, " ").trim();
  }

  function buildActiveChatRescanDbRawMap(rows) {
    const byTurn = new Map();
    for (const row of Array.isArray(rows) ? rows : []) {
      const turnIndex = parseInt(row && row.turn_index, 10);
      const role = String(row && row.role || "").trim().toLowerCase();
      if (isNaN(turnIndex) || turnIndex < 1 || (role !== "user" && role !== "assistant")) continue;
      const entry = byTurn.get(turnIndex) || { turnIndex, user: "", assistant: "", rowCount: 0 };
      const content = normalizeActiveChatRescanCompareText(row && row.content);
      if (role === "user" && !entry.user) entry.user = content;
      if (role === "assistant" && !entry.assistant) entry.assistant = content;
      entry.rowCount += 1;
      byTurn.set(turnIndex, entry);
    }
    return byTurn;
  }

  function buildActiveChatRescanDerivedMap(timelineItems) {
    const byTurn = new Map();
    const derivedTypes = new Set(["memory", "evidence", "direct_evidence", "kg_triple", "episode"]);
    for (const item of Array.isArray(timelineItems) ? timelineItems : []) {
      const turnIndex = parseInt(item && (item.turn_index ?? item.turn_anchor ?? item.source_turn), 10);
      const type = String(item && item.type || "").trim().toLowerCase();
      if (isNaN(turnIndex) || turnIndex < 1 || !derivedTypes.has(type)) continue;
      const entry = byTurn.get(turnIndex) || { turnIndex, memory: 0, evidence: 0, kg: 0, episode: 0, episodeRanges: [], derivedTotal: 0 };
      if (type === "memory") entry.memory += 1;
      else if (type === "evidence" || type === "direct_evidence") entry.evidence += 1;
      else if (type === "kg_triple") entry.kg += 1;
      else if (type === "episode") {
        entry.episode += 1;
        const fromTurn = parseInt(item && item.from_turn, 10);
        const toTurn = parseInt(item && item.to_turn, 10);
        if (!isNaN(fromTurn) && !isNaN(toTurn) && fromTurn > 0 && toTurn >= fromTurn) {
          entry.episodeRanges.push(String(fromTurn) + "-" + String(toTurn));
        }
      }
      entry.derivedTotal += 1;
      byTurn.set(turnIndex, entry);
    }
    return byTurn;
  }

  function buildActiveChatRescanDryRunRows(pairs, dbRawMap, derivedMap) {
    const rows = [];
    for (const pair of Array.isArray(pairs) ? pairs : []) {
      const turnIndex = parseInt(pair && pair.turnIndex, 10);
      if (isNaN(turnIndex) || turnIndex < 1) continue;
      const dbRaw = dbRawMap.get(turnIndex) || null;
      const derived = derivedMap.get(turnIndex) || null;
      const userMatches = !!(dbRaw && dbRaw.user && dbRaw.user === normalizeActiveChatRescanCompareText(pair.userContent));
      const assistantMatches = !!(dbRaw && dbRaw.assistant && dbRaw.assistant === normalizeActiveChatRescanCompareText(pair.assistantContent));
      const rawStatus = userMatches && assistantMatches
        ? "present"
        : dbRaw && (dbRaw.user || dbRaw.assistant)
          ? "mismatch_or_partial"
          : "missing";
      const derivedTotal = derived ? Number(derived.derivedTotal || 0) : 0;
      const derivedStatus = derivedTotal > 0 ? "present" : rawStatus === "missing" ? "not_checked_no_raw" : "missing_suspected";
      rows.push({
        turn_index: turnIndex,
        raw_status: rawStatus,
        derived_status: derivedStatus,
        user_present: !!(dbRaw && dbRaw.user),
        assistant_present: !!(dbRaw && dbRaw.assistant),
        derived_total: derivedTotal,
        memory_count: derived ? Number(derived.memory || 0) : 0,
        evidence_count: derived ? Number(derived.evidence || 0) : 0,
        kg_count: derived ? Number(derived.kg || 0) : 0,
        episode_count: derived ? Number(derived.episode || 0) : 0,
        episode_ranges: derived && Array.isArray(derived.episodeRanges) ? derived.episodeRanges.slice(0, 3) : [],
        preview: String(pair.userContent || "").slice(0, 120),
      });
    }
    return rows;
  }

  function buildActiveChatRescanPairsFromDbRawFallback(activeMessages, dbRawMap) {
    const pairs = [];
    try {
      const activeTexts = new Set(
        (Array.isArray(activeMessages) ? activeMessages : [])
          .map(function(msg) {
            return normalizeActiveChatRescanCompareText(msg && msg.content);
          })
          .filter(Boolean)
      );
      if (activeTexts.size === 0 || !(dbRawMap instanceof Map) || dbRawMap.size === 0) return pairs;

      Array.from(dbRawMap.values())
        .sort(function(a, b) { return Number(a.turnIndex || 0) - Number(b.turnIndex || 0); })
        .forEach(function(entry) {
          const turnIndex = Number(entry && entry.turnIndex);
          const userText = normalizeActiveChatRescanCompareText(entry && entry.user);
          const assistantText = normalizeActiveChatRescanCompareText(entry && entry.assistant);
          if (!Number.isFinite(turnIndex) || turnIndex < 1 || !userText || !assistantText) return;
          const userMatched = activeTexts.has(userText);
          const assistantMatched = activeTexts.has(assistantText);
          if (!userMatched && !assistantMatched) return;
          pairs.push({
            turnIndex,
            userContent: entry.user,
            assistantContent: entry.assistant,
            contextMessages: [],
            endIndex: 0,
            hash: computeOrchestrationDirtyHashOr1c(userText + "\n---assistant---\n" + assistantText),
            source: "active_chat_rescan_db_raw_role_fallback",
            fallbackMatch: assistantMatched ? "assistant" : "user",
          });
        });
    } catch (err) {
      debugLog("buildActiveChatRescanPairsFromDbRawFallback failed:", err && err.message);
    }
    return pairs;
  }

  function summarizeActiveChatRawMessageShape(activeChat, comparableMessages) {
    try {
      const rawMessages = extractActiveChatMessageList(activeChat);
      const rawCount = Array.isArray(rawMessages) ? rawMessages.length : 0;
      const comparableCount = Array.isArray(comparableMessages) ? comparableMessages.length : 0;
      const keySet = new Set();
      const refKeySet = new Set();
      const rawTypes = [];
      let primitiveReferenceCount = 0;
      for (const item of (Array.isArray(rawMessages) ? rawMessages.slice(0, 5) : [])) {
        const itemType = Array.isArray(item) ? "array" : typeof item;
        if (itemType !== "object") {
          const text = String(item == null ? "" : item);
          if (isLikelyReferenceId(text)) primitiveReferenceCount++;
          rawTypes.push(itemType + (isLikelyReferenceId(text) ? ":ref" : ":literal") + ":len" + String(text.length));
          continue;
        }
        if (!item || typeof item !== "object") continue;
        Object.keys(item).slice(0, 30).forEach(function(key) { keySet.add(key); });
        ["saying", "Saying", "sayingId", "SayingId", "messageId", "MessageId", "contentId", "ContentId"].forEach(function(key) {
          if (item[key] != null) refKeySet.add(key);
        });
      }
      const db = getRisuDbSnapshot();
      const dbRootKeys = db && typeof db === "object" ? Object.keys(db).slice(0, 40) : [];
      const activeChatKeys = activeChat && typeof activeChat === "object" && !Array.isArray(activeChat)
        ? Object.keys(activeChat).slice(0, 40)
        : [];
      return {
        raw_count: rawCount,
        comparable_count: comparableCount,
        unparsed_count: Math.max(0, rawCount - comparableCount),
        sample_keys: Array.from(keySet).slice(0, 20),
        reference_keys: Array.from(refKeySet).slice(0, 12),
        raw_sample_types: rawTypes.slice(0, 8),
        primitive_reference_count: primitiveReferenceCount,
        active_chat_keys: activeChatKeys,
        risu_db_root_keys: dbRootKeys,
      };
    } catch {
      return { raw_count: 0, comparable_count: 0, unparsed_count: 0, sample_keys: [], reference_keys: [], raw_sample_types: [], primitive_reference_count: 0, active_chat_keys: [], risu_db_root_keys: [] };
    }
  }

  async function computeActiveChatRescanDryRunPlan(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) throw new Error("missing session id");
    const activeSid = String(await getCurrentChatSessionId() || "").trim();
    if (!activeSid || activeSid !== sid) {
      return { ok: false, notLive: true, error: t('explorer.activeRescan.notLive') };
    }

    const resolvedActiveChat = await resolveCurrentActiveChatObject(sid);
    const messages = resolvedActiveChat.chat ? extractActiveChatComparableMessages(resolvedActiveChat.chat) : [];
    const rawShape = summarizeActiveChatRawMessageShape(resolvedActiveChat.chat, messages);
    const dbRows = await explorerFetchAllChatLogsForSession(sid);
    const timelineResult = await explorerFetchTimelineItemsForSessionDryRun(sid);
    let worldRulesResult = { items: [], count: 0, fetched: false };
    try {
      worldRulesResult = await fetchWorldRules(sid);
    } catch (err) {
      debugLog("active chat rescan world rule count failed:", err && err.message);
    }
    const dbRawMap = buildActiveChatRescanDbRawMap(dbRows);
    let pairSource = "active_chat_role_parse";
    let pairs = buildCompletedTurnPairsFromActiveChatMessages(messages);
    if (pairs.length === 0 && Array.isArray(messages) && messages.length > 0 && dbRawMap.size > 0) {
      const fallbackPairs = buildActiveChatRescanPairsFromDbRawFallback(messages, dbRawMap);
      if (fallbackPairs.length > 0) {
        pairs = fallbackPairs;
        pairSource = "db_raw_role_fallback";
      }
    }
    const derivedMap = buildActiveChatRescanDerivedMap(timelineResult.items);
    const rows = buildActiveChatRescanDryRunRows(pairs, dbRawMap, derivedMap);
    const rawMissingTurns = rows.filter(row => row.raw_status === "missing").map(row => row.turn_index);
    const rawMismatchTurns = rows.filter(row => row.raw_status === "mismatch_or_partial").map(row => row.turn_index);
    const derivedMissingTurns = rows.filter(row => row.derived_status === "missing_suspected").map(row => row.turn_index);
    const worldRuleCount = Number(worldRulesResult && (worldRulesResult.count ?? (Array.isArray(worldRulesResult.items) ? worldRulesResult.items.length : 0)) || 0);
    const worldRuleMissingTurns = worldRuleCount === 0
      ? rows.filter(row => row.raw_status === "present").map(row => row.turn_index)
      : [];
    const processableTurns = Array.from(new Set(rawMissingTurns.concat(rawMismatchTurns, derivedMissingTurns, worldRuleMissingTurns))).sort((a, b) => a - b);

    return {
      ok: true,
      sid,
      resolvedActiveChat,
      messages,
      rawShape,
      dbRows,
      dbRawMap,
      timelineResult,
      worldRulesResult,
      worldRuleCount,
      derivedMap,
      pairSource,
      pairs,
      rows,
      rawMissingTurns,
      rawMismatchTurns,
      derivedMissingTurns,
      worldRuleMissingTurns,
      processableTurns,
    };
  }

  async function runActiveChatRescanDryRun(sessionId) {
    const sid = String(sessionId || "").trim();
    if (!sid) {
      alert(t('rescan.noSession'));
      return false;
    }
    if (_activeChatRescanDryRunState.loading) return false;

    _activeChatRescanDryRunState.loading = true;
    _activeChatRescanDryRunState.error = null;
    _activeChatRescanDryRunState.result = null;
    refreshExplorerUI();

    try {
      const plan = await computeActiveChatRescanDryRunPlan(sid);
      if (!plan.ok && plan.notLive) {
        _activeChatRescanDryRunState.loading = false;
        _activeChatRescanDryRunState.error = plan.error || t('explorer.activeRescan.notLive');
        refreshExplorerUI();
        return false;
      }

      _activeChatRescanDryRunState.loading = false;
      _activeChatRescanDryRunState.result = {
        status: "ok",
        version: "active_chat_rescan_dry_run.v1",
        dry_run_only: true,
        write_attempted: false,
        llm_call_attempted: false,
        rescan_run: false,
        chat_session_id: sid,
        active_chat_source: plan.resolvedActiveChat.source || "none",
        active_message_count: Array.isArray(plan.messages) ? plan.messages.length : 0,
        active_chat_raw_message_count: plan.resolvedActiveChat.chat ? extractActiveChatMessageCount(plan.resolvedActiveChat.chat) : 0,
        active_chat_unparsed_raw_count: plan.rawShape.unparsed_count,
        active_chat_sample_keys: plan.rawShape.sample_keys,
        active_chat_reference_keys: plan.rawShape.reference_keys,
        active_chat_raw_sample_types: plan.rawShape.raw_sample_types,
        active_chat_primitive_reference_count: plan.rawShape.primitive_reference_count,
        active_chat_keys: plan.rawShape.active_chat_keys,
        risu_db_root_keys: plan.rawShape.risu_db_root_keys,
        active_pair_source: plan.pairSource,
        active_pair_count: plan.pairs.length,
        db_chat_log_rows_checked: plan.dbRows.length,
        db_raw_turns_checked: plan.dbRawMap.size,
        timeline_items_checked: plan.timelineResult.items.length,
        scan_limited: !!plan.timelineResult.limited || plan.dbRows.length >= ACTIVE_CHAT_RESCAN_DRY_RUN_CHATLOG_PAGE_LIMIT * 200,
        raw_missing_count: plan.rawMissingTurns.length,
        raw_mismatch_or_partial_count: plan.rawMismatchTurns.length,
        derived_missing_suspected_count: plan.derivedMissingTurns.length,
        world_rule_count: plan.worldRuleCount || 0,
        world_rule_missing_suspected_count: plan.worldRuleMissingTurns.length,
        processable_turn_count: plan.processableTurns.length,
        raw_missing_turns: plan.rawMissingTurns.slice(0, 50),
        raw_mismatch_or_partial_turns: plan.rawMismatchTurns.slice(0, 50),
        derived_missing_suspected_turns: plan.derivedMissingTurns.slice(0, 50),
        world_rule_missing_suspected_turns: plan.worldRuleMissingTurns.slice(0, 50),
        processable_turns: plan.processableTurns.slice(0, 80),
        rows_preview: plan.rows.filter(row => row.raw_status !== "present" || row.derived_status !== "present").slice(0, 20),
        generated_at: new Date().toISOString(),
      };
      refreshExplorerUI();
      return true;
    } catch (err) {
      _activeChatRescanDryRunState.loading = false;
      _activeChatRescanDryRunState.error = err && err.message ? err.message : String(err || "active chat scan failed");
      refreshExplorerUI();
      return false;
    }
  }

  function buildSessionNormalizeRepairEntriesFromDryRunPlan(plan) {
    const rawMissingSet = new Set((Array.isArray(plan && plan.rawMissingTurns) ? plan.rawMissingTurns : []).map(function(turn) { return Number(turn); }));
    if (rawMissingSet.size === 0) return [];
    return (Array.isArray(plan && plan.pairs) ? plan.pairs : [])
      .map(function(pair) {
        const turnIndex = Number(pair && pair.turnIndex);
        if (!Number.isFinite(turnIndex) || turnIndex < 1 || !rawMissingSet.has(turnIndex)) return null;
        return sanitizeChatLogRepairEntry({
          turn_index: turnIndex,
          user_content: String(pair && pair.userContent || ""),
          assistant_content: String(pair && pair.assistantContent || ""),
          source: "active_chat_session_normalize",
        }, "active_chat_session_normalize");
      })
      .filter(Boolean);
  }

  function buildSessionNormalizeTargetTurnsFromDryRunPlan(plan) {
    const mismatch = new Set((Array.isArray(plan && plan.rawMismatchTurns) ? plan.rawMismatchTurns : []).map(function(turn) { return Number(turn); }));
    return normalizeTurnIndexList(Array.isArray(plan && plan.processableTurns) ? plan.processableTurns : [])
      .filter(function(turn) { return !mismatch.has(Number(turn)); });
  }

  function renderSessionNormalizeResultHtml(result) {
    if (!result) return "";
    const after = result.counts_after && typeof result.counts_after === "object" ? result.counts_after : {};
    const plan = result.plan && typeof result.plan === "object" ? result.plan : {};
    const repair = result.repair_replay && typeof result.repair_replay === "object" ? result.repair_replay : {};
    const rescan = result.rescan && typeof result.rescan === "object" ? result.rescan : {};
    const reindex = result.reindex && typeof result.reindex === "object" ? result.reindex : {};
    const artifactCounts = rescan.artifact_counts && typeof rescan.artifact_counts === "object" ? rescan.artifact_counts : {};
    const warnings = Array.isArray(result.warnings) ? result.warnings : [];
    const reviewTurns = Array.isArray(result.review_needed_turns) ? result.review_needed_turns : [];
    const hierarchy = rescan.hierarchy_backfill && typeof rescan.hierarchy_backfill === "object" ? rescan.hierarchy_backfill : null;
    const hierarchyBlocked = hierarchy ? formatHierarchyBlockedSummary(hierarchy) : "";
    const reindexReason = reindex.reason != null ? String(reindex.reason) : "";
    const reindexAction = reindex.ui_action != null ? String(reindex.ui_action) : "";
    const artifactSummary = [
      "mem:" + Number(artifactCounts.memories || 0),
      "evi:" + Number(artifactCounts.evidence || 0),
      "kg:" + Number(artifactCounts.kg_triples || 0),
      "rule:" + Number(artifactCounts.world_rules || 0),
      "ep:" + Number(artifactCounts.episode_summaries || 0),
      "ch:" + Number(artifactCounts.chapter_summaries || 0),
      "arc:" + Number(artifactCounts.arc_summaries || 0),
      "saga:" + Number(artifactCounts.saga_digests || 0),
      "vec:" + Number((artifactCounts.vectors_upserted || 0) + (reindex.upserted || 0)),
    ].join(" / ");
    return '<div class="mo-reindex-result">' +
      '<strong>✅ 세션 정상화 완료</strong> ' + escapeAttr(String(result.status || "")) +
      '<br>raw turns: ' + Number(after.raw_complete_turns || 0) + '/' + Number(after.raw_turns || 0) +
      ' / memories: ' + Number(after.memories || 0) +
      ' / evidence: ' + Number(after.direct_evidence || 0) +
      ' / kg: ' + Number(after.kg_triples || 0) +
      ' / world rules: ' + Number(after.world_rules || 0) +
      ' / episodes: ' + Number(after.episode_summaries || 0) +
      ' / chapters: ' + Number(after.chapter_summaries || 0) +
      ' / arcs: ' + Number(after.arc_summaries || 0) +
      ' / sagas: ' + Number(after.saga_digests || 0) +
      '<br>repair: missing roles ' + Number(repair.total_missing_role_count || 0) +
      ' / repaired roles ' + Number(repair.total_repaired_role_count || 0) +
      ' / conflicts ' + Number(repair.total_conflict_role_count || 0) +
      '<br>rescan: candidates ' + Number(rescan.candidate_count || 0) +
      ' / succeeded ' + Number(rescan.succeeded || 0) +
      ' / failed ' + Number(rescan.failed || 0) +
      ' / skipped ' + Number(rescan.skipped || 0) +
      '<br>reindex: candidates ' + Number(reindex.candidates || reindex.candidate_count || 0) +
      ' / upserted ' + Number(reindex.upserted || 0) +
      ' / skipped ' + Number(reindex.skipped || reindex.skipped_count || 0) +
      (reindexReason ? ' / reason: ' + escapeAttr(reindexReason) : '') +
      '<br>artifacts: ' + escapeAttr(artifactSummary) +
      (Number(plan.raw_import_candidates || 0) > 0 ? '<br>raw import candidates: ' + Number(plan.raw_import_candidates || 0) : '') +
      (reviewTurns.length > 0 ? '<br><span style="color:#f59e0b">review needed: ' + escapeAttr(formatTurnIndexPreview(reviewTurns, 16)) + '</span>' : '') +
      (reindexAction ? '<br><span style="color:#93c5fd">reindex action: ' + escapeAttr(reindexAction) + '</span>' : '') +
      (hierarchyBlocked ? '<br><span style="color:#f59e0b">hierarchy blocked: ' + escapeAttr(hierarchyBlocked) + '</span>' : '') +
      (warnings.length > 0 ? '<br><span style="font-size:11px;color:#f59e0b">warnings: ' + escapeAttr(warnings.slice(0, 6).join(" / ")) + '</span>' : '') +
      '<br><span style="font-size:11px;color:#888">삭제/rollback 없음 · visible trim은 DB 삭제 근거로 사용하지 않음</span>' +
      '</div>';
  }

  async function normalizeSession(sessionId, maxItems, options = {}) {
    const sid = String(sessionId || "").trim();
    const opts = options && typeof options === "object" ? options : {};
    if (!sid) {
      alert(t('rescan.noSession'));
      return false;
    }
    if (_sessionNormalizeState.loading) return false;
    const limit = Math.max(1, Math.min(parseInt(maxItems, 10) || 1000, 5000));
    const shortId = sid.length > 30 ? sid.slice(0, 15) + "…" + sid.slice(-10) : sid;
    const confirmed = await showConfirmModal(
      "Session Normalize",
      "[Session Normalize]\n\n" +
      "대상 세션: " + shortId + "\n" +
      "max_items: " + String(limit) + "\n\n" +
      "현재 챗과 DB를 비교해 누락 원문, 파생 기억, 세계 규칙, 에피소드/계층 요약, 벡터 색인을 순서대로 복구합니다.\n" +
      "이 작업은 DB 삭제나 rollback을 하지 않으며 /cut, /del, context trim으로 보이는 기록이 줄어도 DB 행을 삭제하지 않습니다.\n\n" +
      t('common.confirmContinue')
    );
    if (!confirmed) return false;

    _sessionNormalizeState.loading = true;
    _sessionNormalizeState.error = null;
    _sessionNormalizeState.result = null;
    _sessionNormalizeState.job = null;
    _sessionNormalizeState.planWarning = "";
    refreshExplorerUI();

    let repairEntries = [];
    let turnIndices = [];
    let planMeta = {};
    try {
      const activeSid = String(await getCurrentChatSessionId() || "").trim();
      if (activeSid && activeSid === sid) {
        const plan = await computeActiveChatRescanDryRunPlan(sid);
        if (plan && plan.ok) {
          repairEntries = buildSessionNormalizeRepairEntriesFromDryRunPlan(plan);
          turnIndices = buildSessionNormalizeTargetTurnsFromDryRunPlan(plan);
          planMeta = {
            active_chat_plan_status: "ok",
            active_chat_pair_count: Array.isArray(plan.pairs) ? plan.pairs.length : 0,
            active_chat_raw_missing_count: Array.isArray(plan.rawMissingTurns) ? plan.rawMissingTurns.length : 0,
            active_chat_raw_mismatch_count: Array.isArray(plan.rawMismatchTurns) ? plan.rawMismatchTurns.length : 0,
            active_chat_derived_missing_count: Array.isArray(plan.derivedMissingTurns) ? plan.derivedMissingTurns.length : 0,
          };
        }
      } else {
        planMeta = { active_chat_plan_status: "skipped_not_active_session", active_session_id: activeSid || "" };
      }
    } catch (err) {
      _sessionNormalizeState.planWarning = err && err.message ? err.message : String(err || "active chat plan failed");
      planMeta = { active_chat_plan_status: "failed", active_chat_plan_error: _sessionNormalizeState.planWarning };
    }

    try {
      const result = await safeCall(
        () => bridgeFetch("/admin/session-normalize", {
          method: "POST",
          body: {
            chat_session_id: sid,
            max_items: limit,
            batch_size: 50,
            repair_entries: repairEntries,
            turn_indices: turnIndices,
            force_reindex: true,
            dry_run: false,
            skip_rescan: !!opts.skipRescan,
            client_meta: buildAdminRuntimeClientMeta(Object.assign({ source: "explorer_session_normalize" }, planMeta)),
          },
        }),
        null, "normalizeSession"
      );
      if (acceptAdminBackgroundJob("session_normalize", _sessionNormalizeState, result)) {
        refreshExplorerUI({ preserveScroll: true });
        return true;
      }
      _sessionNormalizeState.loading = false;
      if (!result || result.status !== "ok") {
        _sessionNormalizeState.error = (result && result.detail) ? result.detail : "session normalize failed";
        refreshExplorerUI();
        return false;
      }
      _sessionNormalizeState.result = result;
      refreshExplorerUI();
      return true;
    } catch (err) {
      _sessionNormalizeState.loading = false;
      _sessionNormalizeState.error = err && err.message ? err.message : String(err || "session normalize failed");
      refreshExplorerUI();
      return false;
    }
  }

  async function runActiveChatRecentRebuild(sessionId, maxTurns, orderMode) {
    const sid = String(sessionId || "").trim();
    if (!sid) {
      alert(t('rescan.noSession'));
      return false;
    }
    if (_activeChatRecentRebuildState.loading) return false;

    const limit = Math.max(1, Math.min(parseInt(maxTurns, 10) || ACTIVE_CHAT_RECENT_REBUILD_DEFAULT_TURNS, ACTIVE_CHAT_RECENT_REBUILD_MAX_TURNS));
    const normalizedOrder = String(orderMode || ACTIVE_CHAT_REBUILD_DEFAULT_ORDER).trim().toLowerCase() === "recent" ? "recent" : "oldest";
    const shortId = sid.length > 30 ? sid.slice(0, 15) + "…" + sid.slice(-10) : sid;
    const confirmed = await showConfirmModal(
      "Recent Active Chat Rebuild",
      "[Recent Active Chat Rebuild]\n\n" +
      "session: " + shortId + "\n" +
      "recent turns: " + String(limit) + "\n\n" +
      "order: " + (normalizedOrder === "recent" ? "recent missing turns" : "first missing turns") + "\n\n" +
      "현재 RisuAI 활성 챗에서 누락된 최근 턴만 /complete-turn으로 재전송합니다.\n" +
      "이 작업은 DB를 변경하고 Critic/derived artifact 재생성을 시도합니다.\n\n" +
      t('common.confirmContinue')
    );
    if (!confirmed) return false;

    _activeChatRecentRebuildState.loading = true;
    _activeChatRecentRebuildState.error = null;
    _activeChatRecentRebuildState.result = null;
    refreshExplorerUI();

    try {
      const plan = await computeActiveChatRescanDryRunPlan(sid);
      if (!plan.ok) {
        _activeChatRecentRebuildState.loading = false;
        _activeChatRecentRebuildState.error = plan.error || "active chat rebuild plan failed";
        refreshExplorerUI();
        return false;
      }

      const worldRuleMissingSet = new Set((Array.isArray(plan.worldRuleMissingTurns) ? plan.worldRuleMissingTurns : []).map(function(turn) { return Number(turn); }));
      const safeProcessableTurns = plan.rows
        .filter(function(row) {
          const rawStatus = String(row && row.raw_status || "");
          const derivedStatus = String(row && row.derived_status || "");
          const turn = Number(row && row.turn_index);
          return rawStatus === "missing" ||
            (rawStatus === "present" && derivedStatus === "missing_suspected") ||
            (rawStatus === "present" && worldRuleMissingSet.has(turn));
        })
        .map(function(row) { return Number(row.turn_index); })
        .filter(function(turn) { return Number.isFinite(turn) && turn > 0; });
      const blockedMismatchTurns = Array.isArray(plan.rawMismatchTurns) ? plan.rawMismatchTurns.slice() : [];
      const targetTurns = normalizedOrder === "recent"
        ? safeProcessableTurns.slice(-limit)
        : safeProcessableTurns.slice(0, limit);
      const targetTurnSet = new Set(targetTurns.map(function(turn) { return Number(turn); }));
      const pairByTurn = new Map();
      for (const pair of plan.pairs) {
        const turn = Number(pair && pair.turnIndex);
        if (Number.isFinite(turn) && turn > 0 && targetTurnSet.has(turn)) pairByTurn.set(turn, pair);
      }

      let saved = 0;
      let exists = 0;
      let queued = 0;
      let skipped = 0;
      const derivedOnlyTurns = [];
      const details = [];
      for (const turn of targetTurns) {
        const pair = pairByTurn.get(Number(turn));
        if (!pair) {
          skipped++;
          details.push({ turn_index: turn, status: "skipped", reason: "pair_not_found" });
          continue;
        }
        const row = plan.rows.find(function(item) { return Number(item && item.turn_index) === Number(turn); }) || {};
        const worldRuleForce = worldRuleMissingSet.has(Number(turn));
        const forceDerived = row.derived_status === "missing_suspected" || worldRuleForce;
        const result = await backfillOneActiveChatCompletedTurn(sid, pair, {
          forceCompleteTurn: forceDerived,
          source: "active_chat_recent_rebuild",
        });
        const status = String(result && result.status || "unknown");
        if (status === "saved") saved++;
        else if (status === "exists") {
          exists++;
          if (result && result.derivedRescanNeeded) derivedOnlyTurns.push(Number(turn));
        }
        else if (status === "queued") queued++;
        else skipped++;
        details.push({
          turn_index: turn,
          status,
          raw_status: row.raw_status || "",
          derived_status: row.derived_status || "",
          world_rule_rejudge: !!worldRuleForce,
          force_derived_rebuild: !!forceDerived,
          memories_saved: result && result.memoriesSaved,
          evidence_saved: result && result.evidenceSaved,
          kg_triples_saved: result && result.kgTriplesSaved,
          subjective_entity_memories_saved: result && result.subjectiveEntityMemoriesSaved,
          world_rules_saved: result && result.worldRulesSaved,
          reason: result && result.reason,
        });
        scheduleTimelinePostCompleteTurnRefresh(sid, turn);
      }

      const derivedRescanResult = derivedOnlyTurns.length > 0
        ? await runDerivedArtifactBackfillOnlyForSession(sid, derivedOnlyTurns)
        : null;
      const episodeBackfillResult = await runEpisodeBackfillOnlyForSession(sid, targetTurns);
      const episodeBackfill = episodeBackfillResult && episodeBackfillResult.episode_backfill
        ? episodeBackfillResult.episode_backfill
        : null;

      _activeChatRecentRebuildState.loading = false;
      _activeChatRecentRebuildState.result = {
        status: queued > 0 || (derivedRescanResult && derivedRescanResult.status === "failed") ? "partial" : "ok",
        version: "active_chat_recent_rebuild.v1",
        chat_session_id: sid,
        requested_limit: limit,
        target_order: normalizedOrder,
        target_turns: targetTurns,
        blocked_mismatch_turns: blockedMismatchTurns.slice(0, 50),
        saved,
        exists,
        queued,
        skipped,
        total_targeted: targetTurns.length,
        details,
        derived_rescan_turns: derivedOnlyTurns,
        derived_rescan_result: derivedRescanResult || null,
        derived_rescan_status: String((derivedRescanResult && derivedRescanResult.status) || ""),
        episode_backfill: episodeBackfill,
        episode_backfill_status: String((episodeBackfill && episodeBackfill.status) || (episodeBackfillResult && episodeBackfillResult.status) || ""),
        episode_backfill_result: episodeBackfillResult || null,
        write_attempted: targetTurns.length > 0,
        llm_call_attempted: saved > 0 || queued > 0 || derivedOnlyTurns.length > 0,
        generated_at: new Date().toISOString(),
      };
      if (episodeBackfill && Number(episodeBackfill.generated || 0) > 0) {
        updateRuntimeState("lastEpisodeGeneration", "ok", {
          detail: "episode backfill generated " + String(Number(episodeBackfill.generated || 0)) + " ranges",
          reason: "active_chat_recent_rebuild_episode_backfill",
        });
      }
      updateRuntimeState("lastActiveChatBackfill", queued > 0 ? "warn" : "ok", {
        detail: "recent active chat rebuild " + String(saved) + " saved / " + String(exists) + " existing / " + String(queued) + " queued",
        turnIndex: targetTurns.length > 0 ? targetTurns[targetTurns.length - 1] : null,
        reason: "manual_recent_rebuild",
      });
      refreshExplorerUI();
      runActiveChatRescanDryRun(sid).catch(function(err) {
        debugLog("recent rebuild post-scan failed:", err && err.message);
      });
      setTimeout(function() {
        loadTimelineData(true, { sessionId: sid, skipRuntimeSessionResolve: true }).catch(function(err) {
          debugLog("recent rebuild timeline refresh failed:", err && err.message);
        });
      }, 400);
      return true;
    } catch (err) {
      _activeChatRecentRebuildState.loading = false;
      _activeChatRecentRebuildState.error = err && err.message ? err.message : String(err || "recent rebuild failed");
      refreshExplorerUI();
      return false;
    }
  }

  function buildChatLogRepairEntriesFromRows(rows, sourceType) {
    const byTurn = new Map();
    for (const row of Array.isArray(rows) ? rows : []) {
      const turnIndex = parseInt(row && row.turn_index, 10);
      const role = String(row && row.role || "").trim().toLowerCase();
      if (isNaN(turnIndex) || turnIndex < 1) continue;
      if (role !== "user" && role !== "assistant") continue;

      const entry = byTurn.get(turnIndex) || {
        turn_index: turnIndex,
        user_content: "",
        assistant_content: "",
        created_at: String(row && row.created_at || ""),
        source: sourceType,
      };
      if (role === "user" && !entry.user_content) entry.user_content = String(row.content || "");
      if (role === "assistant" && !entry.assistant_content) entry.assistant_content = String(row.content || "");
      if (!entry.created_at && row && row.created_at) entry.created_at = String(row.created_at);
      byTurn.set(turnIndex, entry);
    }
    return Array.from(byTurn.values())
      .map(entry => sanitizeChatLogRepairEntry(entry, sourceType))
      .filter(Boolean)
      .sort((left, right) => left.turn_index - right.turn_index);
  }

  function buildChatLogRepairEntriesFromComparableMessages(messages, trackedTurnIndex, sourceType) {
    const comparableMessages = Array.isArray(messages)
      ? messages.map(extractComparableMessageRoleAndContent).filter(Boolean)
      : [];
    if (comparableMessages.length === 0) return [];

    const ledgerState = buildRollbackTurnLedgerOr1f(comparableMessages, trackedTurnIndex);
    const maxCompletedTurn = Math.max(
      Number(ledgerState && ledgerState.trackedTurnIndex || 0),
      Number(ledgerState && ledgerState.assistantMessageCount || 0),
      0
    );
    const byTurn = new Map();

    for (const ledgerEntry of Array.isArray(ledgerState && ledgerState.entries) ? ledgerState.entries : []) {
      const comparable = comparableMessages[ledgerEntry.messageIndex];
      const turnIndex = parseInt(ledgerEntry && ledgerEntry.turnIndex, 10);
      const role = String(ledgerEntry && ledgerEntry.role || "").trim().toLowerCase();
      if (!comparable || isNaN(turnIndex) || turnIndex < 1 || turnIndex > maxCompletedTurn) continue;
      if (role !== "user" && role !== "assistant") continue;

      const content = String(comparable.content || "");
      if (!content) continue;

      const entry = byTurn.get(turnIndex) || {
        turn_index: turnIndex,
        user_content: "",
        assistant_content: "",
        created_at: "",
        source: String(sourceType || "active_chat"),
      };
      if (role === "user" && !entry.user_content) entry.user_content = content;
      if (role === "assistant" && !entry.assistant_content) entry.assistant_content = content;
      byTurn.set(turnIndex, entry);
    }

    return Array.from(byTurn.values())
      .map(entry => sanitizeChatLogRepairEntry(entry, sourceType || "active_chat"))
      .filter(Boolean)
      .sort((left, right) => left.turn_index - right.turn_index);
  }

  async function buildChatLogRepairReplayFallbackBundleFromActiveChat(sessionId) {
    const sid = String(sessionId || "").trim();
    const bundle = {
      entries: [],
      journalCount: 0,
      deletedSnapshotCount: 0,
      activeChatMessageCount: 0,
      candidateTurnIndices: [],
      sourceType: "active_chat",
      liveSessionMatch: false,
      activeSessionId: "",
    };
    if (!sid) return bundle;

    try {
      bundle.activeSessionId = String(await getCurrentChatSessionId() || "").trim();
    } catch {
      bundle.activeSessionId = "";
    }
    if (!bundle.activeSessionId || bundle.activeSessionId !== sid) {
      return bundle;
    }

    bundle.liveSessionMatch = true;
    try {
      const dryRunPlan = await computeActiveChatRescanDryRunPlan(sid);
      if (!dryRunPlan || !dryRunPlan.ok || dryRunPlan.rawMismatchTurns.length > 0 || dryRunPlan.derivedMissingTurns.length > 0) {
        bundle.blocked = true;
        bundle.blockedReason = dryRunPlan && dryRunPlan.rawMismatchTurns && dryRunPlan.rawMismatchTurns.length > 0
          ? "active_chat_turn_mismatch_present"
          : "active_chat_derived_mismatch_present";
        bundle.rawMismatchTurns = dryRunPlan && Array.isArray(dryRunPlan.rawMismatchTurns) ? dryRunPlan.rawMismatchTurns.slice(0, 20) : [];
        bundle.derivedMissingTurns = dryRunPlan && Array.isArray(dryRunPlan.derivedMissingTurns) ? dryRunPlan.derivedMissingTurns.slice(0, 20) : [];
        return bundle;
      }
      if (!Array.isArray(dryRunPlan.rawMissingTurns) || dryRunPlan.rawMissingTurns.length === 0) {
        bundle.blocked = true;
        bundle.blockedReason = "active_chat_has_no_raw_missing_turns";
        return bundle;
      }
      bundle.safeMissingTurns = dryRunPlan.rawMissingTurns.slice();
    } catch (err) {
      bundle.blocked = true;
      bundle.blockedReason = "active_chat_dry_run_preflight_failed: " + (err && err.message ? err.message : "unknown");
      return bundle;
    }
    const comparableMessages = await getCurrentActiveChatComparableMessages();
    bundle.activeChatMessageCount = Array.isArray(comparableMessages) ? comparableMessages.length : 0;
    const trackedTurnIndex = Math.max(loadTurnCounter(sid), getSessionTurnIndex(sid), 0);
    const safeMissingSet = new Set((bundle.safeMissingTurns || []).map(function(turn) { return Number(turn); }));
    bundle.entries = buildChatLogRepairEntriesFromComparableMessages(comparableMessages, trackedTurnIndex, "active_chat")
      .filter(function(entry) { return safeMissingSet.has(Number(entry && entry.turn_index)); });
    bundle.candidateTurnIndices = bundle.entries.map(entry => entry.turn_index);
    return bundle;
  }

  async function captureChatLogRestoreSnapshot(sessionId, turnIndex) {
    const sid = String(sessionId || "").trim();
    const targetTurn = parseInt(turnIndex, 10);
    if (!sid || isNaN(targetTurn) || targetTurn < 1) return 0;

    let sourceRows = [];
    const currentRows = Array.isArray(_explorer.chatLogs.items) ? _explorer.chatLogs.items : [];
    if (_explorer.selectedSessionId === sid && !_explorer.chatLogs.hasMore) {
      sourceRows = currentRows.filter(row => row && row.chat_session_id === sid);
    } else {
      sourceRows = await explorerFetchAllChatLogsForSession(sid);
    }

    const snapshotRows = sourceRows.filter(row => row && parseInt(row.turn_index, 10) >= targetTurn);
    const snapshotEntries = buildChatLogRepairEntriesFromRows(snapshotRows, "delete_snapshot");
    if (snapshotEntries.length > 0) {
      saveChatLogRestoreSnapshotEntries(sid, snapshotEntries);
    }
    return snapshotEntries.length;
  }

  async function rescanSession(sessionId, maxItems, options) {
    const opts = options && typeof options === "object" ? options : {};
    const targetTurnIndices = normalizeTurnIndexList(opts.turnIndices);
    if (!sessionId) {
      alert(t('rescan.noSession'));
      return false;
    }
    if (_rescanState.loading) return false;

    if (!opts.skipConfirm) {
      const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
      const confirmed = await showConfirmModal("Rescan",
        "[Rescan]\n\n" +
        t('rescan.confirmTarget') + " " + shortId + "\n" +
        "max_items: " + maxItems + "\n" +
        (targetTurnIndices.length > 0 ? "target turns: " + formatTurnIndexPreview(targetTurnIndices) + "\n" : "") +
        "\n" +
        t('rescan.confirmDesc') + "\n" + t('common.confirmContinue')
      );
      if (!confirmed) return false;
    }

    _rescanState.loading = true;
    _rescanState.error = null;
    _rescanState.result = null;
    _rescanState.job = null;
    refreshExplorerUI();

    try {
      const result = await safeCall(
        () => bridgeFetch("/admin/rescan", {
          method: "POST",
          body: {
            chat_session_id: sessionId,
            max_items: parseInt(maxItems) || 50,
            turn_indices: targetTurnIndices,
            background: true,
            client_meta: buildAdminRuntimeClientMeta(Object.assign({
              episode_interval_turns: settings.episodeIntervalTurns || DEFAULT_SETTINGS.episodeIntervalTurns,
              force_world_rule_backfill: true,
              source: "explorer_rescan",
            }, opts.clientMeta && typeof opts.clientMeta === "object" ? opts.clientMeta : {})),
          },
          timeoutMs: getRequestTimeoutSettingMs(),
        }),
        null, "rescanSession"
      );

      if (acceptAdminBackgroundJob("rescan", _rescanState, result)) {
        refreshExplorerUI({ preserveScroll: true });
        return true;
      }

      _rescanState.loading = false;

      if (!result || result.status !== "ok") {
        _rescanState.error = (result && result.detail) ? result.detail : t('rescan.failed');
        refreshExplorerUI();
        return false;
      }

      _rescanState.result = result;
      refreshExplorerUI();
      return true;

    } catch (err) {
      _rescanState.loading = false;
      _rescanState.error = err.message || t('common.unknownError');
      refreshExplorerUI();
      return false;
    }
  }

  async function runEpisodeBackfillOnlyForSession(sessionId, turnIndices) {
    const sid = String(sessionId || "").trim();
    if (!sid) return { status: "skipped", reason: "missing_session_id" };
    try {
      const result = await safeCall(
        () => bridgeFetch("/admin/rescan", {
          method: "POST",
          body: {
            chat_session_id: sid,
            max_items: 1,
            turn_indices: normalizeTurnIndexList(turnIndices),
            client_meta: buildAdminRuntimeClientMeta({
              episode_interval_turns: settings.episodeIntervalTurns || DEFAULT_SETTINGS.episodeIntervalTurns,
              episode_backfill_only: true,
              force_episode_backfill: true,
              force_world_rule_backfill: true,
              source: "episode_backfill_only",
            }),
          },
          timeoutMs: getRequestTimeoutSettingMs(),
        }),
        null, "runEpisodeBackfillOnlyForSession"
      );
      if (!result || result.status !== "ok") {
        return {
          status: "failed",
          reason: (result && (result.detail || result.reason || result.status)) || "episode_backfill_failed",
          result,
        };
      }
      return result;
    } catch (err) {
      return { status: "failed", reason: err && err.message ? err.message : String(err || "episode_backfill_failed") };
    }
  }

  async function runDerivedArtifactBackfillOnlyForSession(sessionId, turnIndices) {
    const sid = String(sessionId || "").trim();
    const normalizedTurnIndices = normalizeTurnIndexList(turnIndices);
    if (!sid || normalizedTurnIndices.length === 0) return { status: "skipped", reason: "missing_session_or_turns" };
    try {
      const result = await safeCall(
        () => bridgeFetch("/admin/rescan", {
          method: "POST",
          body: {
            chat_session_id: sid,
            max_items: normalizedTurnIndices.length,
            turn_indices: normalizedTurnIndices,
            client_meta: buildAdminRuntimeClientMeta({
              episode_interval_turns: settings.episodeIntervalTurns || DEFAULT_SETTINGS.episodeIntervalTurns,
              derived_backfill_only: true,
              force_derived_rebuild: true,
              force_episode_backfill: true,
              force_world_rule_backfill: true,
              source: "active_chat_recent_rebuild_raw_exists",
            }),
          },
          timeoutMs: getRequestTimeoutSettingMs(),
        }),
        null, "runDerivedArtifactBackfillOnlyForSession"
      );
      if (!result || result.status !== "ok") {
        return {
          status: "failed",
          reason: (result && (result.detail || result.reason || result.status)) || "derived_backfill_failed",
          result,
        };
      }
      return result;
    } catch (err) {
      return { status: "failed", reason: err && err.message ? err.message : String(err || "derived_backfill_failed") };
    }
  }

  async function maybeRescanDerivedArtifactsForTurns(sessionId, turnIndices) {
    const normalizedTurnIndices = normalizeTurnIndexList(turnIndices);
    if (!sessionId || normalizedTurnIndices.length === 0) {
      return { ran: false, ok: false, result: null, error: null };
    }

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    const confirmed = await showConfirmModal(
      "Rebuild Derived Records",
      "[Rebuild Derived Records]\n\n" +
      "session: " + shortId + "\n" +
      "turns: " + formatTurnIndexPreview(normalizedTurnIndices) + "\n\n" +
      "복구된 raw chat_logs를 기준으로 누락된 Memory / Direct Evidence / KG / state를 다시 만들 수 있습니다.\n" +
      "This runs Rescan only for restored turns that still have no memory.\n\n" +
      "Run Rescan now?"
    );
    if (!confirmed) {
      return { ran: false, ok: false, result: null, error: null };
    }

    _chatLogRepairState.loading = true;
    setChatLogRepairProgress("working", "Repair Replay 완료. Rescan으로 누락 Memory / Direct Evidence / KG / state를 다시 생성하고 있습니다.");
    refreshExplorerUI();

    const ok = await rescanSession(sessionId, normalizedTurnIndices.length, {
      skipConfirm: true,
      turnIndices: normalizedTurnIndices,
      clientMeta: {
        force_derived_rebuild: true,
        force_episode_backfill: true,
        force_world_rule_backfill: true,
      },
    });

    _chatLogRepairState.loading = false;
    return {
      ran: true,
      ok,
      result: ok ? (_rescanState.result || null) : null,
      error: ok ? null : (_rescanState.error || null),
    };
  }

  async function explorerRepairChatLogs() {
    const sessionId = explorerSessionId();
    if (!sessionId) {
      try { alert(t('rescan.noSession')); } catch { /* silent */ }
      return false;
    }
    if (_chatLogRepairState.loading) return false;

    let candidateBundle = buildChatLogRepairReplayCandidateBundle(sessionId);
    if (candidateBundle.entries.length === 0) {
      const activeChatBundle = await buildChatLogRepairReplayFallbackBundleFromActiveChat(sessionId);
      if (activeChatBundle.entries.length > 0) {
        candidateBundle = activeChatBundle;
      } else {
        _chatLogRepairState.error = null;
        _chatLogRepairState.result = null;
        const blockedReason = activeChatBundle && activeChatBundle.blockedReason ? String(activeChatBundle.blockedReason) : "";
        setChatLogRepairProgress(
          "done",
          blockedReason
            ? "Repair Replay 후보가 보류되었습니다: " + blockedReason + ". raw mismatch가 있는 상태에서는 active chat 원문을 자동 삽입하지 않습니다."
            : activeChatBundle.liveSessionMatch
            ? "점검 완료: 활성 chat 기준으로 재생성할 수 있는 완료 턴이 없습니다."
            : "Repair Replay 후보가 없습니다. failed queue / local delete snapshot이 비어 있고 선택 세션이 현재 활성 chat이 아니라 live preflight를 수행할 수 없습니다."
        );
        refreshExplorerUI();
        return false;
      }
    }

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    _chatLogRepairState.loading = true;
    _chatLogRepairState.error = null;
    _chatLogRepairState.result = null;
    setChatLogRepairProgress(
      "working",
      candidateBundle.sourceType === "active_chat"
        ? "활성 chat 기준 Repair Replay 후보를 점검하고 있습니다."
        : "Repair Replay 후보를 점검하고 있습니다."
    );
    refreshExplorerUI();

    try {
      const dryRunResult = await bridgeFetch("/turns/repair-replay", {
        method: "POST",
        body: {
          chat_session_id: sessionId,
          dry_run: true,
          entries: candidateBundle.entries,
        },
        timeoutMs: getRequestTimeoutSettingMs(),
      });

      if (!dryRunResult || dryRunResult.status === "error") {
        throw new Error((dryRunResult && dryRunResult.detail) || "repair replay dry-run failed");
      }

      const missingRoleCount = Number(dryRunResult.total_missing_role_count || 0);
      const conflictRoleCount = Number(dryRunResult.total_conflict_role_count || 0);
      const candidateTurns = candidateBundle.candidateTurnIndices;

      if (missingRoleCount <= 0) {
        _chatLogRepairState.loading = false;
        if (conflictRoleCount > 0) {
          setChatLogRepairProgress("done", "점검 완료: 누락 role은 없지만 conflict가 남아 있어 자동 복구를 보류했습니다.");
          try { alert("누락된 chat_logs는 없지만 기존 DB 내용과 다른 conflict가 있어 자동 복구를 보류했습니다."); } catch { /* silent */ }
        } else if (candidateBundle.sourceType === "active_chat") {
          setChatLogRepairProgress("done", "점검 완료: 활성 chat 기준으로 복구할 누락 chat_logs가 없습니다.");
          try { alert("활성 chat 기준으로 점검한 결과 누락된 chat_logs가 없습니다."); } catch { /* silent */ }
        } else {
          await removeFailedQueueItemsByTurn(sessionId, candidateTurns, "save");
          clearChatLogRestoreSnapshotEntries(sessionId, candidateTurns);
          setChatLogRepairProgress("done", "점검 완료: 복구할 누락 chat_logs가 없어 local 후보를 정리했습니다.");
          try { alert("누락된 chat_logs가 없어 local repair 후보를 정리했습니다.\n삭제된 파생 Memory/Direct Evidence/KG/state는 자동 복원되지 않으며, 필요하면 Rescan을 실행해 raw chat_logs 기준으로 다시 만들어야 합니다."); } catch { /* silent */ }
        }
        refreshExplorerUI();
        return true;
      }

      const confirmed = await showConfirmModal(
        "Repair Replay",
        "[Repair Replay]\n\n" +
        "session: " + shortId + "\n" +
        "candidate turns: " + formatTurnIndexPreview(candidateTurns) + "\n" +
        "missing roles: " + missingRoleCount + "\n" +
        "conflicts: " + conflictRoleCount + "\n" +
        "failed queue: " + candidateBundle.journalCount + " / delete snapshot: " + candidateBundle.deletedSnapshotCount +
        (candidateBundle.sourceType === "active_chat" ? " / active chat msgs: " + Number(candidateBundle.activeChatMessageCount || 0) : "") + "\n\n" +
        t('explorer.chatLogs.repairReplayScope') + "\n\n" +
        t('common.confirmContinue')
      );
      if (!confirmed) {
        _chatLogRepairState.loading = false;
        setChatLogRepairProgress("done", "Repair Replay가 취소되었습니다.");
        refreshExplorerUI();
        return false;
      }

      setChatLogRepairProgress("working", "Repair Replay를 실행하고 있습니다.");
      refreshExplorerUI();

      const replayResult = await bridgeFetch("/turns/repair-replay", {
        method: "POST",
        body: {
          chat_session_id: sessionId,
          dry_run: false,
          entries: candidateBundle.entries,
        },
        timeoutMs: getRequestTimeoutSettingMs(),
      });

      if (!replayResult || replayResult.status === "error") {
        throw new Error((replayResult && replayResult.detail) || "repair replay failed");
      }

      _chatLogRepairState.result = replayResult;
      const repairedTurns = normalizeTurnIndexList(replayResult.repaired_turns || []);
      if (repairedTurns.length > 0) {
        await removeFailedQueueItemsByTurn(sessionId, repairedTurns, "save");
        clearChatLogRestoreSnapshotEntries(sessionId, repairedTurns);
      }

      const replayDoneDetail = "Repair Replay 완료: 복구 role " + Number(replayResult.total_repaired_role_count || 0) + " / conflict " + Number(replayResult.total_conflict_role_count || 0) + " / 실패 턴 " + Number((replayResult.failed_turns || []).length || 0);
      _chatLogRepairState.loading = false;
      setChatLogRepairProgress("done", replayDoneDetail);

      await explorerFetchChatLogs(true);
      await refreshExplorerUI();

      if (repairedTurns.length > 0) {
        const rescanOutcome = await maybeRescanDerivedArtifactsForTurns(sessionId, repairedTurns);
        if (rescanOutcome.ran && rescanOutcome.ok) {
          const rescanResult = rescanOutcome.result || {};
          setChatLogRepairProgress(
            "done",
            replayDoneDetail +
              " / Rescan 성공 턴 " + Number(rescanResult.succeeded || 0) +
              " / 실패 턴 " + Number(rescanResult.failed || 0)
          );
        } else if (rescanOutcome.ran && rescanOutcome.error) {
          setChatLogRepairProgress("done", replayDoneDetail + " / Rescan 실패: " + rescanOutcome.error);
        }
        await refreshExplorerUI();
      }
      return true;
    } catch (err) {
      _chatLogRepairState.loading = false;
      _chatLogRepairState.error = err.message || "repair replay error";
      setChatLogRepairProgress("error", "Repair Replay 오류: " + _chatLogRepairState.error);
      refreshExplorerUI();
      return false;
    }
  }

  // ──────────────────────────────────────────────────────────────
  // [HYPAMEMORY IMPORT — 4th-step #3]
  // ──────────────────────────────────────────────────────────────

  let _hypaImportState = { loading: false, error: null, result: null };

  function normalizeHypaImportSourceTurnIndex(summary, index) {
    const item = summary && typeof summary === "object" ? summary : {};
    const keys = [
      "source_turn_index", "sourceTurnIndex",
      "turn_index", "turnIndex",
      "hypa_turn_index", "hypaTurnIndex",
      "hypa_index", "hypaIndex",
      "index", "idx", "order",
    ];
    for (const key of keys) {
      if (!(key in item)) continue;
      const n = Number(item[key]);
      if (!Number.isFinite(n) || n === 0) continue;
      const whole = Math.trunc(n);
      return whole < 0 ? whole : -Math.abs(whole);
    }
    return -(Number(index || 0) + 1);
  }

  async function importHypaMemory(sessionId) {
    if (!sessionId) {
      alert(t('hypaImport.noSession'));
      return;
    }
    if (_hypaImportState.loading) return;

    // 1. RisuAI에서 현재 챗의 hypaV3Data 읽기
    let hypaData = null;
    try {
      if (!R || typeof R.getCharacter !== "function") {
        _hypaImportState.error = t('hypaImport.noApi');
        refreshExplorerUI();
        return;
      }

      const char = await R.getCharacter();
      if (!char || !Array.isArray(char.chats) || typeof char.chatPage !== "number") {
        _hypaImportState.error = t('hypaImport.noCharData');
        refreshExplorerUI();
        return;
      }

      const activeChat = char.chats[char.chatPage];
      if (!activeChat) {
        _hypaImportState.error = t('hypaImport.noChatFound');
        refreshExplorerUI();
        return;
      }

      hypaData = activeChat.hypaV3Data;
      if (!hypaData || !Array.isArray(hypaData.summaries) || hypaData.summaries.length === 0) {
        _hypaImportState.error = t('hypaImport.noHypaData');
        refreshExplorerUI();
        return;
      }
    } catch (readErr) {
      _hypaImportState.error = t('hypaImport.readFailed') + ": " + readErr.message;
      refreshExplorerUI();
      return;
    }

    const summaries = hypaData.summaries;
    const count = summaries.length;

    const shortId = sessionId.length > 30 ? sessionId.slice(0, 15) + "…" + sessionId.slice(-10) : sessionId;
    const confirmed = await showConfirmModal("HypaMemory Import",
      "[HypaMemory Import]\n\n" +
      t('hypaImport.confirmTarget') + " " + shortId + "\n" +
      t('hypaImport.confirmCount') + " " + count + "\n\n" +
      t('hypaImport.confirmDesc') + "\n" + t('common.confirmContinue')
    );
    if (!confirmed) return;

    _hypaImportState.loading = true;
    _hypaImportState.error = null;
    _hypaImportState.result = null;
    refreshExplorerUI();

    try {
      // 2. summaries를 backend로 전송
      const payload = {
        chat_session_id: sessionId,
        summaries: summaries.map((s, idx) => ({
          text: s.text || "",
          is_important: !!s.isImportant,
          tags: Array.isArray(s.tags) ? s.tags : [],
          category: s.categoryId || "",
          source_turn_index: normalizeHypaImportSourceTurnIndex(s, idx),
        })),
      };

      const result = await safeCall(
        () => bridgeFetch("/import/hypamemory", {
          method: "POST",
          body: payload,
          timeoutMs: getRequestTimeoutSettingMs(),
        }),
        null, "importHypaMemory"
      );

      _hypaImportState.loading = false;

      if (!result || result.status !== "ok") {
        _hypaImportState.error = (result && result.detail) ? result.detail : t('hypaImport.requestFailed');
        refreshExplorerUI();
        return;
      }

      _hypaImportState.result = { total: count, detail: result.detail || "" };
      refreshExplorerUI();

    } catch (err) {
      _hypaImportState.loading = false;
      _hypaImportState.error = err.message || t('common.unknownError');
      refreshExplorerUI();
    }
  }

  // ──────────────────────────────────────────────────────────────
  // [DB EDITING — Sprint 2-F: LOGIC]
  // ──────────────────────────────────────────────────────────────

  function explorerIsEditing(type, id) {
    return _explorer.editingItem && _explorer.editingItem.type === type && _explorer.editingItem.id === id;
  }

  function explorerStartEdit(type, id, currentFields) {
    _explorer.editingItem = { type, id };
    _explorer.editFields = { ...currentFields };
    if (type === "mem" && _explorer.editFields.importance !== undefined && _explorer.editFields.importance !== null && _explorer.editFields.importance !== "") {
      _explorer.editFields.importance = formatMemoryImportanceDisplay(_explorer.editFields.importance);
    }
    _explorer.editStatus = "";
    _explorer.editError = "";
    // 편집 대상 항목은 자동 확장
    const key = type + "_" + id;
    _explorer.expandedItems.add(key);
  }

  function explorerCancelEdit() {
    _explorer.editingItem = null;
    _explorer.editFields = {};
    _explorer.editStatus = "";
    _explorer.editError = "";
  }

  /** Memory 수정 PATCH 호출 */
  async function explorerPatchMemory(memoryId) {
    const sid = explorerSessionId();
    if (!sid) {
      _explorer.editError = t('explorer.edit.noSession');
      _explorer.editStatus = "error";
      return false;
    }

    const fields = _explorer.editFields;

    // summary_json 프론트 사전 검증
    if (fields.summary_json != null && typeof fields.summary_json === "string" && fields.summary_json.trim()) {
      try {
        JSON.parse(fields.summary_json);
      } catch {
        _explorer.editError = t('explorer.edit.invalidJson');
        _explorer.editStatus = "error";
        return false;
      }
    }

    _explorer.editStatus = "saving";
    _explorer.editError = "";

    try {
      const body = { chat_session_id: sid };
      if (fields.summary_json !== undefined) body.summary_json = fields.summary_json;
      if (fields.importance !== undefined) body.importance = normalizeMemoryImportanceDisplayToStore(fields.importance);
      if (fields.archive_wing !== undefined) body.archive_wing = fields.archive_wing;
      if (fields.archive_room !== undefined) body.archive_room = fields.archive_room;

      const result = await bridgeFetch("/explorer/memories/" + memoryId, { method: "PATCH", body });
      if (result && result.status === "ok") {
        _explorer.editStatus = "success";
        debugLog("Memory #" + memoryId + " 수정 완료:", result.updated_fields);
        // 편집 모드 종료 후 목록 갱신
        setTimeout(async () => {
          explorerCancelEdit();
          await explorerLoadTab("memories", true);
          await refreshExplorerUI();
        }, 800);
        return true;
      } else {
        _explorer.editError = (result && result.detail) || t('explorer.edit.patchFailed');
        _explorer.editStatus = "error";
        return false;
      }
    } catch (err) {
      _explorer.editError = err.message || t('common.networkError');
      _explorer.editStatus = "error";
      return false;
    }
  }

