  // memory / kg_triple 개별 삭제 (hard delete, session-aware)
  // ──────────────────────────────────────────────────────────────

  async function explorerDeleteWithPostFallback(postPath, deletePath, debugTag) {
    let postResult = null;
    try {
      postResult = await bridgeFetch(postPath, {
        method: "POST",
        timeoutMs: getRequestTimeoutSettingMs(),
      });
    } catch (postErr) {
      debugLog(debugTag + " POST 경로 실패:", postErr.message || postErr);
    }

    if (postResult && postResult.status === "ok") {
      return postResult;
    }

    let deleteResult = null;
    try {
      deleteResult = await bridgeFetch(deletePath, {
        method: "DELETE",
        timeoutMs: getRequestTimeoutSettingMs(),
      });
    } catch (deleteErr) {
      debugLog(debugTag + " DELETE 경로 실패:", deleteErr.message || deleteErr);
    }

    if (deleteResult && deleteResult.status === "ok") {
      return deleteResult;
    }

    return deleteResult || postResult || null;
  }

