  async function explorerDeleteChatLogTurn(turnIndex) {
    const sid = explorerSessionId();
    if (!sid || !(typeof turnIndex === "number") || turnIndex < 1) {
      debugLog("explorerDeleteChatLogTurn: invalid session or turn", sid, turnIndex);
      return false;
    }

    try {
      try {
        const snapshotCount = await captureChatLogRestoreSnapshot(sid, turnIndex);
        if (snapshotCount > 0) {
          debugLog("explorerDeleteChatLogTurn: saved delete snapshot entries", snapshotCount, "for session", sid, "from turn", turnIndex);
        }
      } catch (snapshotErr) {
        warnLog("explorerDeleteChatLogTurn snapshot capture failed:", snapshotErr.message || snapshotErr);
      }

      const success = await executeAutoRollback(
        sid,
        turnIndex,
        "explorer_chat_log_delete",
        { currentMsgCount: 0, currentTailHash: "explorer_manual" },
        { requestSource: "manual", updateAutoState: false }
      );
      if (!success) {
        try { alert(t('explorer.delete.failed')); } catch { /* silent */ }
        return false;
      }

      await explorerFetchSessions();
      await explorerFetchChatLogs(true);
      await refreshExplorerUI();
      return true;
    } catch (err) {
      debugLog("explorerDeleteChatLogTurn error:", err.message);
      try { alert(t('explorer.delete.error') + ": " + (err.message || t('common.networkError'))); } catch { /* silent */ }
      return false;
    }
  }

