  function explorerFindWorldRuleById(ruleId) {
    const inTrust = _explorer.trust.worldRules.find(r => r.id === ruleId);
    if (inTrust) return inTrust;
    const inAllWorld = (_explorer.worldGraph.allRules || []).find(r => r.id === ruleId);
    if (inAllWorld) return inAllWorld;
    const inWorld = _explorer.worldGraph.rules.find(r => r.id === ruleId);
    if (inWorld) return inWorld;
    return null;
  }

