  function renderTableReadSection() {
    const state = _tableReadState;
    if (!_timelineState.sessionsLoading && (!Array.isArray(_timelineState.sessions) || !_timelineState.sessions.length)) {
      tableReadResolveSessionDefaults().then(() => {
        if (_settingsActiveTab === "table_read") tableReadRefreshUI();
      }).catch(function() {});
    }
    const statusType = state.status === "ok" ? "ok" : state.status === "running" ? "wait" : state.status === "fail" ? "fail" : "unknown";
    return '<div class="mo-table-read-panel">' +
      '<div class="mo-section">' + escapeAttr(t("tableRead.title")) + '</div>' +
      '<div class="mo-status mo-status-' + escapeAttr(statusType) + '">' + escapeAttr(state.message || t("tableRead.status.idle")) + '</div>' +
      '<div class="mo-table-read-layout">' +
        '<div class="mo-table-read-left">' +
          renderTableReadLlmSettingsPanel(settings) +
        '</div>' +
        '<div class="mo-table-read-right">' +
          '<div class="mo-settings-card">' +
            renderTableReadSessionSelect() +
            '<div class="mo-inline-actions">' +
              '<button class="mo-btn mo-btn-info" id="mo-table-read-load"' + (state.loading ? " disabled" : "") + '>' + escapeAttr(t("tableRead.button.loadEntities")) + '</button>' +
            '</div>' +
          '</div>' +
          '<div class="mo-settings-card">' +
            '<div class="mo-section">' + escapeAttr(t("tableRead.section.entities")) + '</div>' +
            renderTableReadEntities() +
          '</div>' +
        '</div>' +
      '</div>' +
      renderTableReadLiveOutputTrace() +
    '</div>';
  }

  function attachTableReadEvents() {
    const root = document.getElementById("mo-table-read-root") || document;
    bindSettingsRangeSyncEvents(root);
    syncSettingsRangesFromInputs(root);
    bindPasswordToggleEvents(root);
    const tableReadTestBtn = document.getElementById("mo-test-call-table-read");
    if (tableReadTestBtn && tableReadTestBtn.dataset.tableReadTestBound !== "1") {
      tableReadTestBtn.addEventListener("click", async () => {
        const resultEl = document.getElementById("mo-table-read-llm-test-result") || document.getElementById("mo-test-result");
        tableReadTestBtn.disabled = true;
        try {
          await runTableReadLlmConnectionTest(resultEl);
        } finally {
          tableReadTestBtn.disabled = false;
        }
      });
      tableReadTestBtn.dataset.tableReadTestBound = "1";
    }
    const sessionSelect = document.getElementById("mo-table-read-session");
    if (sessionSelect) sessionSelect.addEventListener("change", () => {
      _tableReadState.sourceSessionId = String(sessionSelect.value || "").trim();
      _tableReadState.entityBundles = [];
      _tableReadState.selectedEntityKeys = [];
      _tableReadState.draftResult = null;
      _tableReadState.simulateResult = null;
      _tableReadState.reviewResult = null;
      _tableReadState.reviseResult = null;
      tableReadRefreshUI();
    });
    const loadBtn = document.getElementById("mo-table-read-load");
    if (loadBtn) loadBtn.addEventListener("click", () => loadTableReadEntities());
    const draftBtn = document.getElementById("mo-table-read-draft");
    if (draftBtn) draftBtn.addEventListener("click", () => runTableReadDraft());
    const simulateBtn = document.getElementById("mo-table-read-simulate");
    if (simulateBtn) simulateBtn.addEventListener("click", () => runTableReadSimulate());
    const reviewBtn = document.getElementById("mo-table-read-review");
    if (reviewBtn) reviewBtn.addEventListener("click", () => runTableReadReview());
    const reviseBtn = document.getElementById("mo-table-read-revise");
    if (reviseBtn) reviseBtn.addEventListener("click", () => runTableReadRevise());
    document.querySelectorAll("[data-table-read-copy-revised]").forEach((btn) => {
      btn.addEventListener("click", () => copyTableReadRevisedDraft());
    });
  }

  function getPromptEditorDefinitions() {
    return PROMPT_EDITOR_DEFINITIONS.slice();
  }

  function getPromptEditorEntry(promptName) {
    const normalized = String(promptName || "").trim();
    if (!normalized) return null;
    if (!_promptEditor.items[normalized]) {
      _promptEditor.items[normalized] = {
        name: normalized,
        filename: "",
        content: "",
        draft: "",
        updated_at: null,
        size: 0,
        loaded: false,
        error: "",
      };
    }
    return _promptEditor.items[normalized];
  }

  function setPromptEditorStatus(type, message) {
    _promptEditor.statusType = String(type || "idle");
    _promptEditor.statusMessage = String(message || "");
  }

  function hasDirtyPromptEditorDrafts() {
    return getPromptEditorDefinitions().some((def) => {
      const entry = getPromptEditorEntry(def.name);
      if (!entry) return false;
      return String(entry.draft || "") !== String(entry.content || "");
    });
  }

  function applyPromptEditorPrompt(prompt) {
    const promptName = String((prompt || {}).name || "").trim();
    if (!promptName) return;
    const entry = getPromptEditorEntry(promptName);
    if (!entry) return;
    const content = String((prompt || {}).content || "");
    entry.name = promptName;
    entry.filename = String((prompt || {}).filename || entry.filename || "");
    entry.content = content;
    entry.draft = content;
    entry.updated_at = prompt && prompt.updated_at != null ? Number(prompt.updated_at) : null;
    entry.size = prompt && prompt.size != null ? Number(prompt.size) : content.length;
    entry.loaded = true;
    entry.error = "";
  }

  function setPromptEditorDraft(promptName, value) {
    const entry = getPromptEditorEntry(promptName);
    if (!entry) return;
    entry.draft = String(value || "");
  }

  function syncPromptEditorDirtyState(promptName) {
    if (typeof document === "undefined") return;
    const entry = getPromptEditorEntry(promptName);
    if (!entry) return;
    const dirty = String(entry.draft || "") !== String(entry.content || "");
    const labelEl = document.querySelector('[data-prompt-dirty="' + promptName + '"]');
    if (labelEl) {
      labelEl.textContent = dirty ? t("settings.prompts.statusDirty") : t("settings.prompts.statusSaved");
      labelEl.classList.toggle("is-dirty", dirty);
    }
    const saveBtn = document.querySelector('[data-prompt-save="' + promptName + '"]');
    if (saveBtn) {
      saveBtn.disabled = !dirty || _promptEditor.savingName === promptName;
    }
  }

  function renderPromptEditorSection() {
    const defs = getPromptEditorDefinitions();
    if (!defs.length) {
      return '<div class="mo-note">' + escapeAttr(t("settings.prompts.empty")) + '</div>';
    }

    const statusType = _promptEditor.statusType && _promptEditor.statusType !== "idle"
      ? _promptEditor.statusType
      : "unknown";
    const statusHtml = _promptEditor.statusMessage
      ? '<div class="mo-status mo-status-' + escapeAttr(statusType) + '">' + escapeAttr(_promptEditor.statusMessage) + '</div>'
      : '';

    const cardsHtml = defs.map((def) => {
      const entry = getPromptEditorEntry(def.name) || {};
      const draft = entry.draft != null ? String(entry.draft) : String(entry.content || "");
      const dirty = draft !== String(entry.content || "");
      const updatedAtText = entry.updated_at
        ? formatDashboardTimestampLocal(Number(entry.updated_at) * 1000, { includeDate: true })
        : "-";
      const sizeText = Number.isFinite(Number(entry.size)) ? String(Number(entry.size)) + ' B' : '-';
      const filename = entry.filename || def.filename;
      const saveDisabled = (!dirty || _promptEditor.savingName === def.name) ? ' disabled' : '';
      const reloadDisabled = _promptEditor.savingName === def.name ? ' disabled' : '';
      const errorHtml = entry.error
        ? '<div class="mo-status mo-status-fail">' + escapeAttr(entry.error) + '</div>'
        : '';

      return ''
        + '<div class="mo-prompt-card" data-prompt-card="' + escapeAttr(def.name) + '">'
        +   '<div class="mo-prompt-card-head">'
        +     '<div>'
        +       '<div class="mo-prompt-card-title">' + escapeAttr(filename) + '</div>'
        +       '<div class="mo-prompt-card-desc">' + escapeAttr(t(def.descriptionKey)) + '</div>'
        +     '</div>'
        +     '<div class="mo-prompt-card-meta">'
        +       escapeAttr(t("settings.prompts.updatedAt")) + ': ' + escapeAttr(updatedAtText)
        +       ' · ' + escapeAttr(t("settings.prompts.size")) + ': ' + escapeAttr(sizeText)
        +     '</div>'
        +   '</div>'
        +   '<div class="mo-prompt-card-state' + (dirty ? ' is-dirty' : '') + '" data-prompt-dirty="' + escapeAttr(def.name) + '">' + escapeAttr(dirty ? t("settings.prompts.statusDirty") : t("settings.prompts.statusSaved")) + '</div>'
        +   '<textarea class="mo-prompt-textarea" data-prompt-textarea="' + escapeAttr(def.name) + '" rows="16" spellcheck="false">' + escapeAttr(draft) + '</textarea>'
        +   '<div class="mo-prompt-actions">'
        +     '<button class="mo-btn mo-btn-primary" data-prompt-save="' + escapeAttr(def.name) + '"' + saveDisabled + '>' + t("settings.prompts.saveBtn") + '</button>'
        +     '<button class="mo-btn mo-btn-info" data-prompt-reload="' + escapeAttr(def.name) + '"' + reloadDisabled + '>' + t("settings.prompts.reloadBtn") + '</button>'
        +   '</div>'
        +   errorHtml
        + '</div>';
    }).join("");

    return ''
      + '<div class="mo-prompt-toolbar">'
      +   '<div class="mo-note">' + escapeAttr(t("settings.prompts.note")) + '</div>'
      +   '<button class="mo-btn mo-btn-info" id="mo-prompt-refresh-btn"' + (_promptEditor.loading ? ' disabled' : '') + '>' + t("settings.prompts.refreshBtn") + '</button>'
      + '</div>'
      + statusHtml
      + '<div class="mo-prompt-list">' + cardsHtml + '</div>';
  }

  async function fetchPromptEditorPrompt(promptName) {
    const data = await bridgeFetch("/prompts/" + encodeURIComponent(promptName));
    if (!data || data.status !== "ok" || !data.prompt) {
      throw new Error(t("settings.prompts.loadFailed"));
    }
    applyPromptEditorPrompt(data.prompt);
  }

  function refreshPromptEditorUI() {
    if (typeof document === "undefined") return;
    const root = document.getElementById("mo-prompt-editor-root");
    if (!root) return;
    root.innerHTML = renderPromptEditorSection();
    attachPromptEditorEvents();
  }

  async function loadPromptEditor(force = false) {
    if (_promptEditor.loading) return false;
    if (_promptEditor.loaded && !force) return true;

    _promptEditor.loading = true;
    setPromptEditorStatus("wait", t("settings.prompts.loading"));
    refreshPromptEditorUI();
    try {
      const defs = getPromptEditorDefinitions();
      for (let i = 0; i < defs.length; i += 1) {
        await fetchPromptEditorPrompt(defs[i].name);
      }
      _promptEditor.loaded = true;
      setPromptEditorStatus("idle", "");
      return true;
    } catch (err) {
      setPromptEditorStatus("fail", err && err.message ? err.message : t("settings.prompts.loadFailed"));
      return false;
    } finally {
      _promptEditor.loading = false;
      refreshPromptEditorUI();
    }
  }

  async function reloadPromptEditorPrompt(promptName) {
    const entry = getPromptEditorEntry(promptName);
    const dirty = entry && String(entry.draft || "") !== String(entry.content || "");
    if (dirty && !confirm(t("settings.prompts.reloadConfirm"))) {
      return false;
    }

    _promptEditor.loading = true;
    setPromptEditorStatus("wait", t("settings.prompts.loading"));
    refreshPromptEditorUI();
    try {
      await fetchPromptEditorPrompt(promptName);
      _promptEditor.loaded = true;
      setPromptEditorStatus("idle", "");
      return true;
    } catch (err) {
      const message = err && err.message ? err.message : t("settings.prompts.loadFailed");
      if (entry) entry.error = message;
      setPromptEditorStatus("fail", message);
      return false;
    } finally {
      _promptEditor.loading = false;
      refreshPromptEditorUI();
    }
  }

  async function savePromptEditorPrompt(promptName) {
    const entry = getPromptEditorEntry(promptName);
    if (!entry) return false;

    const content = String(entry.draft || "");
    if (!content.trim()) {
      const message = t("settings.prompts.emptyReject");
      entry.error = message;
      setPromptEditorStatus("fail", message);
      refreshPromptEditorUI();
      return false;
    }

    _promptEditor.savingName = promptName;
    entry.error = "";
    setPromptEditorStatus("wait", t("settings.prompts.loading"));
    refreshPromptEditorUI();
    try {
      const data = await bridgeFetch("/prompts/" + encodeURIComponent(promptName), {
        method: "PUT",
        body: { content },
      });
      if (!data || data.status !== "ok" || !data.prompt) {
        throw new Error(t("settings.prompts.saveFailed"));
      }
      applyPromptEditorPrompt(data.prompt);
      setPromptEditorStatus("ok", t("settings.status.saved"));
      return true;
    } catch (err) {
      const message = err && err.message ? err.message : t("settings.prompts.saveFailed");
      entry.error = message;
      setPromptEditorStatus("fail", message);
      return false;
    } finally {
      _promptEditor.savingName = "";
      refreshPromptEditorUI();
    }
  }

  function attachPromptEditorEvents() {
    if (typeof document === "undefined") return;

    const refreshBtn = document.getElementById("mo-prompt-refresh-btn");
    if (refreshBtn) {
      refreshBtn.addEventListener("click", async (e) => {
        e.stopPropagation();
        if (_promptEditor.loading) return;
        if (hasDirtyPromptEditorDrafts() && !confirm(t("settings.prompts.reloadConfirm"))) {
          return;
        }
        await loadPromptEditor(true);
      });
    }

    document.querySelectorAll("[data-prompt-textarea]").forEach((textarea) => {
      textarea.addEventListener("input", () => {
        const promptName = textarea.getAttribute("data-prompt-textarea") || "";
        setPromptEditorDraft(promptName, textarea.value);
        syncPromptEditorDirtyState(promptName);
      });
      textarea.addEventListener("click", (e) => e.stopPropagation());
    });

    document.querySelectorAll("[data-prompt-save]").forEach((btn) => {
      btn.addEventListener("click", async (e) => {
        e.stopPropagation();
        const promptName = btn.getAttribute("data-prompt-save") || "";
        if (!promptName) return;
        await savePromptEditorPrompt(promptName);
      });
    });

    document.querySelectorAll("[data-prompt-reload]").forEach((btn) => {
      btn.addEventListener("click", async (e) => {
        e.stopPropagation();
        const promptName = btn.getAttribute("data-prompt-reload") || "";
        if (!promptName) return;
        await reloadPromptEditorPrompt(promptName);
      });
    });
  }

