        if (debugForceIdleBtn) {
          debugForceIdleBtn.textContent = isDebugIdleReentryArmed()
            ? t('settings.debug.forceIdleCancelBtn')
            : t('settings.debug.forceIdleBtn');
        }
        if (debugForceIdleStatus) {
          debugForceIdleStatus.textContent = isDebugIdleReentryArmed()
            ? t('settings.debug.forceIdleArmed')
            : t('settings.debug.forceIdleOff');
        }
